                                    $artifactValidationOk = $false
                                }

                                if ($reportPureSignalActionPresent -and $summaryTriagePureSignalSafeBypassActionPresent) {
                                    $reportPureSignalManualAction = [string](Get-JsonValue $reportPureSignalAction "manualAction")
                                    $reportPureSignalCommandSteps = @(Get-JsonArray $reportPureSignalAction "commandSteps")
                                    $reportPureSignalExpectedArtifacts = @(Get-JsonArray $reportPureSignalAction "expectedArtifacts")
                                    $reportPureSignalCommandStepCount = [int](Get-NumericValueOrDefault (Get-JsonValue $reportPureSignalAction "commandStepCount") $reportPureSignalCommandSteps.Count)
                                    $reportPureSignalExpectedArtifactCount = [int](Get-NumericValueOrDefault (Get-JsonValue $reportPureSignalAction "expectedArtifactCount") $reportPureSignalExpectedArtifacts.Count)

                                    foreach ($pureSignalStringSpec in @(
                                            @{ Summary = $summaryTriagePureSignalSafeBypassActionId; Report = [string](Get-JsonValue $reportPureSignalAction "actionId"); Name = "triagePureSignalSafeBypassActionId" },
                                            @{ Summary = $summaryTriagePureSignalSafeBypassActionStageId; Report = [string](Get-JsonValue $reportPureSignalAction "stageId"); Name = "triagePureSignalSafeBypassActionStageId" },
                                            @{ Summary = $summaryTriagePureSignalSafeBypassActionGateId; Report = [string](Get-JsonValue $reportPureSignalAction "gateId"); Name = "triagePureSignalSafeBypassActionGateId" },
                                            @{ Summary = $summaryTriagePureSignalSafeBypassActionCategory; Report = [string](Get-JsonValue $reportPureSignalAction "category"); Name = "triagePureSignalSafeBypassActionCategory" },
                                            @{ Summary = $summaryTriagePureSignalSafeBypassCommandTemplate; Report = [string](Get-JsonValue $reportPureSignalAction "commandTemplate"); Name = "triagePureSignalSafeBypassCommandTemplate" },
                                            @{ Summary = $summaryTriagePureSignalSafeBypassManualAction; Report = $reportPureSignalManualAction; Name = "triagePureSignalSafeBypassManualAction" },
                                            @{ Summary = $summaryTriagePureSignalSafeBypassExpectedArtifact; Report = [string](Get-JsonValue $reportPureSignalAction "expectedArtifact"); Name = "triagePureSignalSafeBypassExpectedArtifact" },
                                            @{ Summary = $summaryTriagePureSignalSafeBypassFollowUp; Report = [string](Get-JsonValue $reportPureSignalAction "followUp"); Name = "triagePureSignalSafeBypassFollowUp" }
                                        )) {
                                        if (-not [string]::Equals([string]$pureSignalStringSpec["Summary"], [string]$pureSignalStringSpec["Report"], [StringComparison]::Ordinal)) {
                                            Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-acceptance-cycle-summary-triage-puresignal-mismatch" "Artifact '$artifactId' $([string]$pureSignalStringSpec["Name"]) does not match '$summaryTriagePath' capture-puresignal-safe-bypass-bench action."
                                            $artifactValidationOk = $false
                                        }
                                    }

                                    foreach ($pureSignalBoolSpec in @(
                                            @{ Summary = $summaryTriagePureSignalSafeBypassActionRequired; Report = Test-Truthy (Get-JsonValue $reportPureSignalAction "requiredForAcceptance"); Name = "triagePureSignalSafeBypassActionRequired" },
                                            @{ Summary = $summaryTriagePureSignalSafeBypassActionManual; Report = -not [string]::IsNullOrWhiteSpace($reportPureSignalManualAction); Name = "triagePureSignalSafeBypassActionManual" }
                                        )) {
                                        if ([bool]$pureSignalBoolSpec["Summary"] -ne [bool]$pureSignalBoolSpec["Report"]) {
                                            Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-acceptance-cycle-summary-triage-puresignal-mismatch" "Artifact '$artifactId' $([string]$pureSignalBoolSpec["Name"])=$([bool]$pureSignalBoolSpec["Summary"]) but '$summaryTriagePath' reports $([bool]$pureSignalBoolSpec["Report"])."
                                            $artifactValidationOk = $false
                                        }
                                    }

                                    $reportPureSignalPriority = Get-NumericValue (Get-JsonValue $reportPureSignalAction "priority")
                                    if (($null -eq $summaryTriagePureSignalSafeBypassActionPriority -and $null -ne $reportPureSignalPriority) -or
                                        ($null -ne $summaryTriagePureSignalSafeBypassActionPriority -and $null -eq $reportPureSignalPriority) -or
                                        ($null -ne $summaryTriagePureSignalSafeBypassActionPriority -and $null -ne $reportPureSignalPriority -and [Math]::Abs([double]$summaryTriagePureSignalSafeBypassActionPriority - [double]$reportPureSignalPriority) -gt 0.000001)) {
                                        Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-acceptance-cycle-summary-triage-puresignal-mismatch" "Artifact '$artifactId' triagePureSignalSafeBypassActionPriority='$summaryTriagePureSignalSafeBypassActionPriority' but '$summaryTriagePath' reports '$reportPureSignalPriority'."
                                        $artifactValidationOk = $false
                                    }

                                    if ($summaryTriagePureSignalSafeBypassCommandStepCount -ne $reportPureSignalCommandStepCount) {
                                        Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-acceptance-cycle-summary-triage-puresignal-mismatch" "Artifact '$artifactId' triagePureSignalSafeBypassCommandStepCount=$summaryTriagePureSignalSafeBypassCommandStepCount but '$summaryTriagePath' reports $reportPureSignalCommandStepCount."
                                        $artifactValidationOk = $false
                                    }
                                    if ($summaryTriagePureSignalSafeBypassExpectedArtifactCount -ne $reportPureSignalExpectedArtifactCount) {
                                        Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-acceptance-cycle-summary-triage-puresignal-mismatch" "Artifact '$artifactId' triagePureSignalSafeBypassExpectedArtifactCount=$summaryTriagePureSignalSafeBypassExpectedArtifactCount but '$summaryTriagePath' reports $reportPureSignalExpectedArtifactCount."
                                        $artifactValidationOk = $false
                                    }

                                    if (-not (Test-StringArraysMatch -Actual $summaryTriagePureSignalSafeBypassCommandSteps -Expected $reportPureSignalCommandSteps)) {
                                        Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-acceptance-cycle-summary-triage-puresignal-mismatch" "Artifact '$artifactId' triagePureSignalSafeBypassCommandSteps does not match '$summaryTriagePath' capture-puresignal-safe-bypass-bench action."
                                        $artifactValidationOk = $false
                                    }
                                    if (-not (Test-StringArraysMatch -Actual $summaryTriagePureSignalSafeBypassExpectedArtifacts -Expected $reportPureSignalExpectedArtifacts)) {
                                        Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-acceptance-cycle-summary-triage-puresignal-mismatch" "Artifact '$artifactId' triagePureSignalSafeBypassExpectedArtifacts does not match '$summaryTriagePath' capture-puresignal-safe-bypass-bench action."
                                        $artifactValidationOk = $false
                                    }
                                }
                            }
                        }
                        catch {
                            Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-acceptance-cycle-summary-triage-json-invalid" "Artifact '$artifactId' could not read triageReportPath '$summaryTriagePath': $($_.Exception.Message)"
                            $artifactValidationOk = $false
                        }
                    }
                }

                $liveAcceptanceCycleEvidence["summaryValid"] = $artifactValidationOk
                if (-not $artifactValidationOk) {
                    $liveAcceptanceCycleEvidence["status"] = "invalid"
                }
                elseif (Test-Truthy $liveAcceptanceCycleEvidence.liveAcceptanceEvidenceReady) {
                    $liveAcceptanceCycleEvidence["status"] = "ready"
                }
                else {
                    $liveAcceptanceCycleEvidence["status"] = "blocked"
                }
            }

            if ($artifactKind -ieq "metrics-json" -or $artifactId -eq "offline-fixture-metrics") {
                if ($artifactId -eq "offline-fixture-metrics") {
                    $sourceEvidenceEngine = Get-FixtureEvidenceEngine $artifactJson
                    $sourceEvidenceTool = [string](Get-JsonValue $artifactJson "tool")
                    $sourceSha256 = Get-FileSha256 $resolvedArtifactPath
                    $sourceWdspBacked = [string]::Equals($sourceEvidenceEngine, "wdsp", [StringComparison]::OrdinalIgnoreCase)
                    $sourceSyntheticFallback = [string]::Equals($sourceEvidenceEngine, "deterministic-synthetic", [StringComparison]::OrdinalIgnoreCase)
                    $sourceRuntimeRid = [string](Get-JsonValue $artifactJson "wdspRuntimeRid")
                    $sourceRuntimePath = [string](Get-JsonValue $artifactJson "wdspRuntimePath")
                    $sourceRuntimePathKind = [string](Get-JsonValue $artifactJson "wdspRuntimePathKind")
                    $sourceRuntimeFileName = [string](Get-JsonValue $artifactJson "wdspRuntimeFileName")
                    $sourceRuntimeLength = [int64](Get-NumericValueOrDefault (Get-JsonValue $artifactJson "wdspRuntimeLength"))
                    $sourceRuntimeSha256 = ([string](Get-JsonValue $artifactJson "wdspRuntimeSha256")).Trim().ToLowerInvariant()
                    $sourceRuntimeStatus = [string](Get-JsonValue $artifactJson "wdspRuntimeStatus")
                    $sourceScenarioCount = [int](Get-JsonValue $artifactJson "scenarioCount")
                    if ($sourceScenarioCount -eq 0) {
                        $sourceScenarioCount = @(Get-JsonArray $artifactJson "scenarios").Count
                    }
                    $sourceComparisonIds = New-Object System.Collections.Generic.HashSet[string]
                    foreach ($entry in @(Get-MetricEvidenceEntries $artifactJson)) {
                        foreach ($comparisonId in @($entry.comparisonIds)) {
                            $comparison = ConvertTo-ComparisonId ([string]$comparisonId)
                            if (-not [string]::IsNullOrWhiteSpace($comparison)) {
                                [void]$sourceComparisonIds.Add($comparison)
                            }
                        }
                    }

                    $offlineFixtureMetricsEvidence["present"] = $true
                    $offlineFixtureMetricsEvidence["artifactId"] = $artifactId
                    $offlineFixtureMetricsEvidence["path"] = $artifactPath
                    $offlineFixtureMetricsEvidence["evidenceEngine"] = $sourceEvidenceEngine
                    $offlineFixtureMetricsEvidence["evidenceTool"] = $sourceEvidenceTool
                    $offlineFixtureMetricsEvidence["wdspBackedEvidence"] = $sourceWdspBacked
                    $offlineFixtureMetricsEvidence["syntheticFallbackEvidence"] = $sourceSyntheticFallback
                    $offlineFixtureMetricsEvidence["scenarioCount"] = $sourceScenarioCount
                    $offlineFixtureMetricsEvidence["comparisonCount"] = $sourceComparisonIds.Count
                    $offlineFixtureMetricsEvidence["sha256"] = $sourceSha256
                    $offlineFixtureMetricsEvidence["wdspRuntimeRid"] = $sourceRuntimeRid
                    $offlineFixtureMetricsEvidence["wdspRuntimePath"] = $sourceRuntimePath
                    $offlineFixtureMetricsEvidence["wdspRuntimePathKind"] = $sourceRuntimePathKind
                    $offlineFixtureMetricsEvidence["wdspRuntimeFileName"] = $sourceRuntimeFileName
                    $offlineFixtureMetricsEvidence["wdspRuntimeLength"] = $sourceRuntimeLength
                    $offlineFixtureMetricsEvidence["wdspRuntimeSha256"] = $sourceRuntimeSha256
                    $offlineFixtureMetricsEvidence["wdspRuntimeStatus"] = $sourceRuntimeStatus
                    $offlineFixtureMetricsEvidence["status"] = if ($sourceWdspBacked) { "ready" } else { "not-ready" }

                    if (-not $sourceWdspBacked) {
                        $engineText = if ([string]::IsNullOrWhiteSpace($sourceEvidenceEngine)) { "missing" } else { $sourceEvidenceEngine }
                        Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "offline-fixture-metrics-not-wdsp-backed" "Artifact '$artifactId' must be generated by run-dsp-wdsp-fixture-matrix.ps1 or run-dsp-wdsp-fixture-evidence.ps1; evidenceEngine='$engineText'."
                        $artifactValidationOk = $false
                    }
                    if ($sourceWdspBacked -and [string]::IsNullOrWhiteSpace($sourceRuntimeSha256)) {
                        Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "offline-fixture-runtime-hash-missing" "Artifact '$artifactId' is WDSP-backed but does not declare wdspRuntimeSha256 for the native runtime used by the fixture run."
                        $artifactValidationOk = $false
                        $offlineFixtureMetricsEvidence["status"] = "not-ready"
                    }
                    if ($sourceWdspBacked -and
                        -not [string]::IsNullOrWhiteSpace($sourceRuntimeStatus) -and
                        -not [string]::Equals($sourceRuntimeStatus, "found", [StringComparison]::OrdinalIgnoreCase)) {
                        Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "offline-fixture-runtime-not-found" "Artifact '$artifactId' is WDSP-backed but reports wdspRuntimeStatus='$sourceRuntimeStatus'."
                        $artifactValidationOk = $false
                        $offlineFixtureMetricsEvidence["status"] = "not-ready"
                    }
                }

                $metricEntries = @(Get-MetricEvidenceEntries $artifactJson)
                if ($metricEntries.Count -eq 0) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "artifact-metrics-missing" "Artifact '$artifactId' does not contain any metric result entries."
                    $artifactValidationOk = $false
                }

                $metricCoverageByScenarioComparison = @{}
                foreach ($metricEntry in $metricEntries) {
                    foreach ($scenarioId in @($metricEntry.scenarioIds)) {
                        $scenario = [string]$scenarioId
                        if ([string]::IsNullOrWhiteSpace($scenario)) {
                            continue
                        }

                        foreach ($comparisonId in @($metricEntry.comparisonIds)) {
                            $comparison = ConvertTo-ComparisonId ([string]$comparisonId)
                            if ([string]::IsNullOrWhiteSpace($comparison)) {
                                continue
                            }

                            $key = "$scenario||$comparison"
                            if (-not $metricCoverageByScenarioComparison.ContainsKey($key)) {
                                $metricCoverageByScenarioComparison[$key] = [ordered]@{
                                    metricIds = @{}
                                    gateOutcomeCount = 0
                                    failedGateCount = 0
                                }
                            }

                            foreach ($metricId in @($metricEntry.metricIds)) {
                                $metric = ConvertTo-MetricId ([string]$metricId)
                                if (-not [string]::IsNullOrWhiteSpace($metric)) {
                                    $metricCoverageByScenarioComparison[$key].metricIds[$metric] = $true
                                }
                            }

                            $metricCoverageByScenarioComparison[$key].gateOutcomeCount += [int]$metricEntry.gateOutcomeCount
                            $metricCoverageByScenarioComparison[$key].failedGateCount += [int]$metricEntry.failedGateCount
                        }
                    }
                }

                foreach ($expectedScenarioId in $expectedScenarioIds) {
                    $scenario = [string]$expectedScenarioId
                    if ([string]::IsNullOrWhiteSpace($scenario)) {
                        continue
                    }

                    $requiredComparisons = @($expectedComparisonIds)
                    if ($requiredComparisons.Count -eq 0 -and $scenarioRequiredComparisons.ContainsKey($scenario)) {
                        $requiredComparisons = @($scenarioRequiredComparisons[$scenario])
                    }

                    $requiredMetrics = @()
                    if ($scenarioRequiredMetrics.ContainsKey($scenario)) {
                        $requiredMetrics = @($scenarioRequiredMetrics[$scenario])
                    }

                    if ($requiredComparisons.Count -eq 0 -or $requiredMetrics.Count -eq 0) {
                        continue
                    }

                    foreach ($requiredComparison in $requiredComparisons) {
                        $comparison = ConvertTo-ComparisonId ([string]$requiredComparison)
                        if ([string]::IsNullOrWhiteSpace($comparison)) {
                            continue
                        }

                        $key = "$scenario||$comparison"
                        $coveredMetricIds = @{}
                        $gateOutcomeCount = 0
                        $failedGateCount = 0
                        if ($metricCoverageByScenarioComparison.ContainsKey($key)) {
                            $coveredMetricIds = $metricCoverageByScenarioComparison[$key].metricIds
                            $gateOutcomeCount = [int]$metricCoverageByScenarioComparison[$key].gateOutcomeCount
                            $failedGateCount = [int]$metricCoverageByScenarioComparison[$key].failedGateCount
                        }

                        $missingMetricIds = New-Object System.Collections.Generic.List[string]
                        foreach ($requiredMetric in $requiredMetrics) {
                            $metric = ConvertTo-MetricId ([string]$requiredMetric)
                            if (-not [string]::IsNullOrWhiteSpace($metric) -and -not $coveredMetricIds.ContainsKey($metric)) {
                                $missingMetricIds.Add($metric) | Out-Null
                            }
                        }

                        $artifactGateOutcomeCount += $gateOutcomeCount
                        $artifactFailedGateCount += $failedGateCount

                        $metricCoverageRecord = [ordered]@{
                            artifactId = $artifactId
                            scenarioId = $scenario
                            comparisonId = $comparison
                            required = $effectiveRequired
                            ok = ($missingMetricIds.Count -eq 0 -and $gateOutcomeCount -gt 0 -and $failedGateCount -eq 0)
                            requiredMetricIds = @($requiredMetrics)
                            coveredMetricIds = @($coveredMetricIds.Keys | Sort-Object)
                            missingMetricIds = @($missingMetricIds.ToArray())
                            gateOutcomeCount = $gateOutcomeCount
                            failedGateCount = $failedGateCount
                        }
                        $artifactMetricCoverage.Add($metricCoverageRecord) | Out-Null

                        if ($missingMetricIds.Count -gt 0) {
                            $artifactMissingMetricCount += $missingMetricIds.Count
                            Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "artifact-metric-missing" "Artifact '$artifactId' metrics are missing required metrics for scenario '$scenario' comparison '$comparison': $($missingMetricIds.ToArray() -join ', ')."
                            $artifactValidationOk = $false
                        }

                        if ($gateOutcomeCount -le 0) {
                            Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "artifact-gate-outcome-missing" "Artifact '$artifactId' metrics are missing gate outcomes for scenario '$scenario' comparison '$comparison'."
                            $artifactValidationOk = $false
                        }

                        if ($failedGateCount -gt 0) {
                            Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "artifact-gate-failed" "Artifact '$artifactId' metrics report $failedGateCount failed gate outcome(s) for scenario '$scenario' comparison '$comparison'."
                            $artifactValidationOk = $false
                        }
                    }
                }
            }

            if ($artifactKind -ieq "comparison-json" -or $artifactId -eq $metricComparisonArtifactId) {
                $metricComparisonEvidence["present"] = $true

                $tool = [string](Get-JsonValue $artifactJson "tool")
                if ($tool -ne "compare-dsp-fixture-metrics") {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "metric-comparison-tool-invalid" "Artifact '$artifactId' must be generated by compare-dsp-fixture-metrics.ps1."
                    $artifactValidationOk = $false
                }

                $fixtureScenarioScope = [string](Get-JsonValue $artifactJson "fixtureScenarioScope")
                $skippedNonFixtureScenarioIds = @(Get-JsonArray $artifactJson "skippedNonFixtureScenarioIds")
                $skippedNonFixtureScenarioCount = [int](Get-JsonValue $artifactJson "skippedNonFixtureScenarioCount")
                if ($skippedNonFixtureScenarioCount -eq 0 -and $skippedNonFixtureScenarioIds.Count -gt 0) {
                    $skippedNonFixtureScenarioCount = $skippedNonFixtureScenarioIds.Count
                }
                $readyForReview = Test-Truthy (Get-JsonValue $artifactJson "readyForReview")
                $metricCoverageReadyForReview = Test-Truthy (Get-JsonValue $artifactJson "metricCoverageReadyForReview")
                $evidenceEngine = [string](Get-JsonValue $artifactJson "evidenceEngine")
                $evidenceTool = [string](Get-JsonValue $artifactJson "evidenceTool")
                $sourceMetricsPath = [string](Get-JsonValue $artifactJson "metricsPath")
                $sourceMetricsSha256 = ([string](Get-JsonValue $artifactJson "metricsSha256")).Trim().ToLowerInvariant()
                $runtimeRid = [string](Get-JsonValue $artifactJson "wdspRuntimeRid")
                $runtimePath = [string](Get-JsonValue $artifactJson "wdspRuntimePath")
                $runtimePathKind = [string](Get-JsonValue $artifactJson "wdspRuntimePathKind")
                $runtimeFileName = [string](Get-JsonValue $artifactJson "wdspRuntimeFileName")
                $runtimeLength = [int64](Get-NumericValueOrDefault (Get-JsonValue $artifactJson "wdspRuntimeLength"))
                $runtimeSha256 = ([string](Get-JsonValue $artifactJson "wdspRuntimeSha256")).Trim().ToLowerInvariant()
                $runtimeStatus = [string](Get-JsonValue $artifactJson "wdspRuntimeStatus")
                $runtimeIdentityReadyForReview = Test-Truthy (Get-JsonValue $artifactJson "wdspRuntimeIdentityReadyForReview")
                if ([string]::IsNullOrWhiteSpace($evidenceTool)) {
                    $evidenceTool = [string](Get-JsonValue $artifactJson "tool")
                }
                $wdspBackedEvidence = Test-Truthy (Get-JsonValue $artifactJson "wdspBackedEvidence")
                $syntheticFallbackEvidence = Test-Truthy (Get-JsonValue $artifactJson "syntheticFallbackEvidence")
                $regressions = [int](Get-JsonValue $artifactJson "regressionCount")
                $gateFailures = [int](Get-JsonValue $artifactJson "gateFailureCount")
                $missingScenarios = @(Get-JsonArray $artifactJson "missingScenarios")
                $missingScenarioCount = [int](Get-JsonValue $artifactJson "missingScenarioCount")
                if ($missingScenarioCount -eq 0 -and $missingScenarios.Count -gt 0) {
                    $missingScenarioCount = $missingScenarios.Count
                }
                $missingCurrent = [int](Get-JsonValue $artifactJson "missingCurrentBaselineCount")
                $missingThetis = [int](Get-JsonValue $artifactJson "missingThetisBaselineCount")
                $missingCandidate = [int](Get-JsonValue $artifactJson "missingCandidateCount")
                $missingMetrics = [int](Get-JsonValue $artifactJson "missingMetricValueCount")
                $candidateComparisons = [int](Get-JsonValue $artifactJson "candidateComparisonCount")
                $comparisonCatalogRequiredMetrics = [int](Get-JsonValue $artifactJson "metricCatalogRequiredMetricCount")
                $comparisonCatalogContractReady = Test-Truthy (Get-JsonValue $artifactJson "metricCatalogAcceptanceContractReady")
                $comparisonCatalogContractProblemIds = @(Get-JsonArray $artifactJson "metricCatalogContractProblemMetricIds")
                $comparisonCatalogContractProblemCount = [int](Get-JsonValue $artifactJson "metricCatalogContractProblemMetricCount")
                if ($comparisonCatalogContractProblemCount -eq 0 -and $comparisonCatalogContractProblemIds.Count -gt 0) {
                    $comparisonCatalogContractProblemCount = $comparisonCatalogContractProblemIds.Count
                }

                $metricComparisonEvidence["reportReadyForReview"] = $readyForReview
                $metricComparisonEvidence["metricCoverageReadyForReview"] = $metricCoverageReadyForReview
                $metricComparisonEvidence["evidenceEngine"] = $evidenceEngine
                $metricComparisonEvidence["evidenceTool"] = $evidenceTool
                $metricComparisonEvidence["wdspBackedEvidence"] = $wdspBackedEvidence
                $metricComparisonEvidence["syntheticFallbackEvidence"] = $syntheticFallbackEvidence
                $metricComparisonEvidence["sourceMetricsPath"] = $sourceMetricsPath
                $metricComparisonEvidence["sourceMetricsSha256"] = $sourceMetricsSha256
                $metricComparisonEvidence["wdspRuntimeRid"] = $runtimeRid
                $metricComparisonEvidence["wdspRuntimePath"] = $runtimePath
                $metricComparisonEvidence["wdspRuntimePathKind"] = $runtimePathKind
                $metricComparisonEvidence["wdspRuntimeFileName"] = $runtimeFileName
                $metricComparisonEvidence["wdspRuntimeLength"] = $runtimeLength
                $metricComparisonEvidence["wdspRuntimeSha256"] = $runtimeSha256
                $metricComparisonEvidence["wdspRuntimeStatus"] = $runtimeStatus
                $metricComparisonEvidence["wdspRuntimeIdentityReadyForReview"] = $runtimeIdentityReadyForReview
                $metricComparisonEvidence["readyForReview"] = ($readyForReview -and $wdspBackedEvidence)
                $metricComparisonEvidence["fixtureScenarioScope"] = $fixtureScenarioScope
                $metricComparisonEvidence["skippedNonFixtureScenarioCount"] = $skippedNonFixtureScenarioCount
                $metricComparisonEvidence["skippedNonFixtureScenarioIds"] = @($skippedNonFixtureScenarioIds)
                $metricComparisonEvidence["regressionCount"] = $regressions
                $metricComparisonEvidence["gateFailureCount"] = $gateFailures
                $metricComparisonEvidence["missingScenarioCount"] = $missingScenarioCount
                $metricComparisonEvidence["missingScenarios"] = @($missingScenarios)
                $metricComparisonEvidence["missingCurrentBaselineCount"] = $missingCurrent
                $metricComparisonEvidence["missingThetisBaselineCount"] = $missingThetis
                $metricComparisonEvidence["missingCandidateCount"] = $missingCandidate
                $metricComparisonEvidence["missingMetricValueCount"] = $missingMetrics
                $metricComparisonEvidence["candidateComparisonCount"] = $candidateComparisons
                $metricComparisonEvidence["metricCatalogRequiredMetricCount"] = $comparisonCatalogRequiredMetrics
                $metricComparisonEvidence["metricCatalogAcceptanceContractReady"] = $comparisonCatalogContractReady
                $metricComparisonEvidence["metricCatalogContractProblemMetricCount"] = $comparisonCatalogContractProblemCount
                $metricComparisonEvidence["metricCatalogContractProblemMetricIds"] = @($comparisonCatalogContractProblemIds)

                if (-not $readyForReview) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "metric-comparison-not-ready" "Artifact '$artifactId' reports readyForReview=false."
                    $artifactValidationOk = $false
                }
                if (-not $comparisonCatalogContractReady) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "metric-comparison-catalog-contract-not-ready" "Artifact '$artifactId' metric catalog contract is not ready for required metrics: $($comparisonCatalogContractProblemIds -join ', ')."
                    $artifactValidationOk = $false
                }
                if (-not $wdspBackedEvidence) {
                    $engineText = if ([string]::IsNullOrWhiteSpace($evidenceEngine)) { "missing" } else { $evidenceEngine }
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "metric-comparison-not-wdsp-backed" "Artifact '$artifactId' must compare WDSP-backed fixture evidence from run-dsp-wdsp-fixture-matrix.ps1 or run-dsp-wdsp-fixture-evidence.ps1; evidenceEngine='$engineText'."
                    $artifactValidationOk = $false
                }
                if ($wdspBackedEvidence -and [string]::IsNullOrWhiteSpace($runtimeSha256)) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "metric-comparison-runtime-hash-missing" "Artifact '$artifactId' must declare wdspRuntimeSha256 copied from the source offline-fixture-metrics artifact."
                    $artifactValidationOk = $false
                    $metricComparisonEvidence["readyForReview"] = $false
                }
                if ($wdspBackedEvidence -and -not $runtimeIdentityReadyForReview) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "metric-comparison-runtime-identity-not-ready" "Artifact '$artifactId' reports wdspRuntimeIdentityReadyForReview=false."
                    $artifactValidationOk = $false
                    $metricComparisonEvidence["readyForReview"] = $false
                }
                if ($candidateComparisons -le 0) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "metric-comparison-candidate-missing" "Artifact '$artifactId' does not compare any candidate metrics."
                    $artifactValidationOk = $false
                }
                if ($regressions -gt 0) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "metric-comparison-regression" "Artifact '$artifactId' reports $regressions metric regression(s)."
                    $artifactValidationOk = $false
                }
                if ($gateFailures -gt 0) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "metric-comparison-gate-failed" "Artifact '$artifactId' reports $gateFailures failed gate outcome(s)."
                    $artifactValidationOk = $false
                }
                if ($missingScenarioCount -gt 0) {
                    $scenarioText = if ($missingScenarios.Count -gt 0) { $missingScenarios -join ', ' } else { "$missingScenarioCount scenario(s)" }
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "metric-comparison-scenario-missing" "Artifact '$artifactId' is missing fixture metric coverage for benchmark scenario(s): $scenarioText."
                    $artifactValidationOk = $false
                }
                if ($missingCurrent -gt 0) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "metric-comparison-current-baseline-missing" "Artifact '$artifactId' is missing current-Zeus baseline coverage for $missingCurrent candidate scenario(s)."
                    $artifactValidationOk = $false
                }
                if ($missingThetis -gt 0) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "metric-comparison-thetis-baseline-missing" "Artifact '$artifactId' is missing Thetis-parity baseline coverage for $missingThetis candidate scenario(s)."
                    $artifactValidationOk = $false
                }
                if ($missingCandidate -gt 0) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "metric-comparison-candidate-coverage-missing" "Artifact '$artifactId' is missing candidate coverage for $missingCandidate benchmark scenario(s)."
                    $artifactValidationOk = $false
                }
                if ($missingMetrics -gt 0) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "metric-comparison-value-missing" "Artifact '$artifactId' is missing $missingMetrics baseline/candidate metric value(s)."
                    $artifactValidationOk = $false
                }

                if ($artifactValidationOk) {
                    $metricComparisonEvidence["status"] = "ready"
                }
                else {
                    $metricComparisonEvidence["status"] = "not-ready"
                }
            }

            if ($artifactKind -ieq "puresignal-safe-bypass-report-json" -or $artifactId -eq $pureSignalSafeBypassArtifactId) {
                $pureSignalSafeBypassEvidence["present"] = $true
                $pureSignalSafeBypassEvidence["path"] = $artifactPath
                $pureSignalSafeBypassEvidence["sha256"] = Get-FileSha256 $resolvedArtifactPath

                $tool = [string](Get-JsonValue $artifactJson "tool")
                $schemaVersion = [int](Get-NumericValueOrDefault (Get-JsonValue $artifactJson "schemaVersion"))
                $readyForReview = Test-Truthy (Get-JsonValue $artifactJson "readyForReview")
                $scenarioId = [string](Get-JsonValue $artifactJson "scenarioId")
                $hardwareTarget = [string](Get-JsonValue $artifactJson "hardwareTarget")
                $disabledPathReady = Test-Truthy (Get-JsonValue $artifactJson "disabledPathReady")
                $enabledPathReady = Test-Truthy (Get-JsonValue $artifactJson "enabledPathReady")
                $capturedModeCount = [int](Get-NumericValueOrDefault (Get-JsonValue $artifactJson "capturedModeCount"))
                $missingModes = @(Get-JsonArray $artifactJson "missingModes")
                $missingModeCount = [int](Get-NumericValueOrDefault (Get-JsonValue $artifactJson "missingModeCount"))
                if ($missingModeCount -eq 0 -and $missingModes.Count -gt 0) {
                    $missingModeCount = $missingModes.Count
                }
                $pureSignalDefaultStatePreserved = Test-Truthy (Get-JsonValue $artifactJson "pureSignalDefaultStatePreserved")
                $defaultBehaviorChangeApproved = Test-Truthy (Get-JsonValue $artifactJson "defaultBehaviorChangeApproved")
                $feedbackStabilityMin = [double](Get-NumericValueOrDefault (Get-JsonValue $artifactJson "feedbackStabilityMin"))
                $feedbackStabilityThreshold = [double](Get-NumericValueOrDefault (Get-JsonValue $artifactJson "feedbackStabilityThreshold"))
                $txMonitorCouplingMax = [double](Get-NumericValueOrDefault (Get-JsonValue $artifactJson "txMonitorCouplingMax"))
                $txMonitorCouplingThreshold = [double](Get-NumericValueOrDefault (Get-JsonValue $artifactJson "txMonitorCouplingThreshold"))
                $clippingCountTotal = [int](Get-NumericValueOrDefault (Get-JsonValue $artifactJson "clippingCountTotal"))
                $gateFailureCount = [int](Get-NumericValueOrDefault (Get-JsonValue $artifactJson "gateFailureCount"))

                $pureSignalSafeBypassEvidence["tool"] = $tool
                $pureSignalSafeBypassEvidence["schemaVersion"] = $schemaVersion
                $pureSignalSafeBypassEvidence["readyForReview"] = $readyForReview
                $pureSignalSafeBypassEvidence["scenarioId"] = $scenarioId
                $pureSignalSafeBypassEvidence["hardwareTarget"] = $hardwareTarget
                $pureSignalSafeBypassEvidence["disabledPathReady"] = $disabledPathReady
                $pureSignalSafeBypassEvidence["enabledPathReady"] = $enabledPathReady
                $pureSignalSafeBypassEvidence["capturedModeCount"] = $capturedModeCount
                $pureSignalSafeBypassEvidence["missingModeCount"] = $missingModeCount
                $pureSignalSafeBypassEvidence["missingModes"] = @($missingModes)
                $pureSignalSafeBypassEvidence["pureSignalDefaultStatePreserved"] = $pureSignalDefaultStatePreserved
                $pureSignalSafeBypassEvidence["defaultBehaviorChangeApproved"] = $defaultBehaviorChangeApproved
                $pureSignalSafeBypassEvidence["feedbackStabilityMin"] = $feedbackStabilityMin
                $pureSignalSafeBypassEvidence["feedbackStabilityThreshold"] = $feedbackStabilityThreshold
                $pureSignalSafeBypassEvidence["txMonitorCouplingMax"] = $txMonitorCouplingMax
                $pureSignalSafeBypassEvidence["txMonitorCouplingThreshold"] = $txMonitorCouplingThreshold
                $pureSignalSafeBypassEvidence["clippingCountTotal"] = $clippingCountTotal
                $pureSignalSafeBypassEvidence["gateFailureCount"] = $gateFailureCount

                if ($tool -ne "summarize-dsp-puresignal-bench") {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "puresignal-safe-bypass-tool-invalid" "Artifact '$artifactId' must be generated by summarize-dsp-puresignal-bench.ps1."
                    $artifactValidationOk = $false
                }
                if ($schemaVersion -lt 1) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "puresignal-safe-bypass-schema-invalid" "Artifact '$artifactId' must declare schemaVersion >= 1."
                    $artifactValidationOk = $false
                }
                if (-not [string]::Equals($scenarioId, "tx-puresignal-safe-bypass", [StringComparison]::Ordinal)) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "puresignal-safe-bypass-scenario-invalid" "Artifact '$artifactId' must declare scenarioId='tx-puresignal-safe-bypass'."
                    $artifactValidationOk = $false
                }
                if (-not $readyForReview) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "puresignal-safe-bypass-not-ready" "Artifact '$artifactId' reports readyForReview=false."
                    $artifactValidationOk = $false
                }
                if (-not $disabledPathReady -or -not $enabledPathReady -or $missingModeCount -gt 0 -or $capturedModeCount -lt 2) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "puresignal-safe-bypass-mode-coverage-missing" "Artifact '$artifactId' must include ready disabled and enabled PureSignal bench captures; missingModes=$($missingModes -join ', ')."
                    $artifactValidationOk = $false
                }
                if (-not $pureSignalDefaultStatePreserved) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "puresignal-safe-bypass-default-state-changed" "Artifact '$artifactId' does not prove PureSignal default/bypass state was preserved."
                    $artifactValidationOk = $false
                }
                if ($defaultBehaviorChangeApproved) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "puresignal-safe-bypass-default-change-approved" "Artifact '$artifactId' must not approve default behavior changes."
                    $artifactValidationOk = $false
                }
                if ($gateFailureCount -gt 0) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "puresignal-safe-bypass-gate-failed" "Artifact '$artifactId' reports $gateFailureCount failed PureSignal safety gate(s)."
                    $artifactValidationOk = $false
                }
                if ($clippingCountTotal -gt 0) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "puresignal-safe-bypass-clipping" "Artifact '$artifactId' reports clippingCountTotal=$clippingCountTotal."
                    $artifactValidationOk = $false
                }
                if ($feedbackStabilityThreshold -gt 0.0 -and $feedbackStabilityMin -lt $feedbackStabilityThreshold) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "puresignal-safe-bypass-feedback-unstable" "Artifact '$artifactId' feedbackStabilityMin=$feedbackStabilityMin is below threshold $feedbackStabilityThreshold."
                    $artifactValidationOk = $false
                }
                if ($txMonitorCouplingThreshold -gt 0.0 -and $txMonitorCouplingMax -gt $txMonitorCouplingThreshold) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "puresignal-safe-bypass-monitor-coupling" "Artifact '$artifactId' txMonitorCouplingMax=$txMonitorCouplingMax is above threshold $txMonitorCouplingThreshold."
                    $artifactValidationOk = $false
                }

                $pureSignalSafeBypassEvidence["status"] = if ($artifactValidationOk) { "ready" } else { "not-ready" }
            }

            $matrixRuns = @(Get-JsonArray $artifactJson "runs")
            $matrixTool = [string](Get-JsonValue $artifactJson "tool")
            if ($matrixTool -eq "run-dsp-live-diagnostics-matrix" -and $matrixRuns.Count -gt 0) {
                $matrixScenarioIds = New-Object System.Collections.Generic.List[string]
                $matrixFailedRunCount = 0
                $matrixNotReadyTraceCount = 0
                $matrixHardBlockerRunCount = 0
                $matrixHardGatePassRunCount = 0
                $matrixStrictPreflightPassRunCount = 0
                $matrixCaptureReadinessStatusCounts = @{}
                $matrixTopCaptureConstraintRunCounts = @{}
                $matrixTopCaptureHardConstraintRunCounts = @{}
                $matrixTopCaptureStatusRunCounts = @{}
                $matrixTopCaptureConstraintSampleCounts = @{}
                $matrixTopCaptureHardConstraintSampleCounts = @{}
                $matrixComparisonStateStatusCounts = @{}
                $matrixComparisonStateStrictRunCount = 0
                $matrixComparisonStateReadyRunCount = 0
                $matrixComparisonStateStrictFailureCount = 0
                $matrixWeakInputSampleCount = 0
                $matrixWeakRecoveredSampleCount = 0
                $matrixWeakDropoutSampleCount = 0
                $matrixHotMakeupSampleCount = 0
                $matrixStrongInputSampleCount = 0
                $matrixMixedWeakStrongTraceCount = 0
                $matrixMixedWeakStrongReadyTraceCount = 0
                $matrixMixedWeakStrongGapWatchRunCount = 0
                $matrixMixedWeakStrongMissingRunCount = 0
                $matrixMixedWeakStrongStatusCounts = @{}
                $matrixArtifactReviewRunCount = 0
                $matrixArtifactRiskScoreMax = 0.0
                $matrixLowEvidenceLiftedSampleCount = 0
                $matrixLowEvidenceLiftedPctMax = $null
                $matrixAudioAlignmentMismatchPctMax = $null
                $matrixArtifactRiskStatusCounts = @{}
                $matrixExpectedSamples = [int](Get-NumericValueOrDefault (Get-JsonValue $artifactJson "samples"))
                $matrixSchemaVersion = [int](Get-NumericValueOrDefault (Get-JsonValue $artifactJson "schemaVersion"))

                foreach ($matrixRun in $matrixRuns) {
                    $runScenarioId = [string](Get-JsonValue $matrixRun "scenarioId")
                    if (-not [string]::IsNullOrWhiteSpace($runScenarioId)) {
                        $matrixScenarioIds.Add($runScenarioId) | Out-Null
                    }

                    if (-not (Test-Truthy (Get-JsonValue $matrixRun "ok"))) {
                        $matrixFailedRunCount++
                    }
                    if (-not (Test-Truthy (Get-JsonValue $matrixRun "readyForBenchmarkTrace"))) {
                        $matrixNotReadyTraceCount++
                    }
                    if ([int](Get-NumericValueOrDefault (Get-JsonValue $matrixRun "hardBlockerSampleCount")) -gt 0) {
                        $matrixHardBlockerRunCount++
                    }
                    if (Test-Truthy (Get-JsonValue $matrixRun "hardGatePass")) {
                        $matrixHardGatePassRunCount++
                    }
                    if (Test-Truthy (Get-JsonValue $matrixRun "strictPreflightPass")) {
                        $matrixStrictPreflightPassRunCount++
                    }
                    $runComparisonStateStrict = Test-Truthy (Get-JsonValue $matrixRun "comparisonStateStrict")
                    $runComparisonStateReady = Test-Truthy (Get-JsonValue $matrixRun "comparisonStateReady")
                    if ($runComparisonStateStrict) {
                        $matrixComparisonStateStrictRunCount++
                        if (-not $runComparisonStateReady) {
                            $matrixComparisonStateStrictFailureCount++
                        }
                    }
                    if ($runComparisonStateReady) {
                        $matrixComparisonStateReadyRunCount++
                    }
                    foreach ($countSpec in @(
                            @{ Map = $matrixCaptureReadinessStatusCounts; Name = [string](Get-JsonValue $matrixRun "captureReadinessStatus"); Increment = 1 },
                            @{ Map = $matrixComparisonStateStatusCounts; Name = [string](Get-JsonValue $matrixRun "comparisonStateStatus"); Increment = 1 },
                            @{ Map = $matrixTopCaptureConstraintRunCounts; Name = [string](Get-JsonValue $matrixRun "topCaptureConstraintName"); Increment = 1 },
                            @{ Map = $matrixTopCaptureHardConstraintRunCounts; Name = [string](Get-JsonValue $matrixRun "topCaptureHardConstraintName"); Increment = 1 },
                            @{ Map = $matrixTopCaptureStatusRunCounts; Name = [string](Get-JsonValue $matrixRun "topCaptureStatusName"); Increment = 1 },
                            @{ Map = $matrixTopCaptureConstraintSampleCounts; Name = [string](Get-JsonValue $matrixRun "topCaptureConstraintName"); Increment = [int](Get-NumericValueOrDefault (Get-JsonValue $matrixRun "topCaptureConstraintCount")) },
                            @{ Map = $matrixTopCaptureHardConstraintSampleCounts; Name = [string](Get-JsonValue $matrixRun "topCaptureHardConstraintName"); Increment = [int](Get-NumericValueOrDefault (Get-JsonValue $matrixRun "topCaptureHardConstraintCount")) }
                        )) {
                        $countName = [string]$countSpec["Name"]
                        $increment = [int]$countSpec["Increment"]
                        if ([string]::IsNullOrWhiteSpace($countName) -or $increment -le 0) {
                            continue
                        }

                        $map = $countSpec["Map"]
                        if (-not $map.ContainsKey($countName)) {
                            $map[$countName] = 0
                        }
                        $map[$countName] = [int]$map[$countName] + $increment
                    }

                    $runOkSamples = [int](Get-NumericValueOrDefault (Get-JsonValue $matrixRun "okSampleCount"))
                    $runFailedSamples = [int](Get-NumericValueOrDefault (Get-JsonValue $matrixRun "failedSampleCount"))
                    if ($matrixExpectedSamples -gt 0 -and ($runOkSamples + $runFailedSamples) -ne $matrixExpectedSamples) {
                        Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-run-sample-count-mismatch" "Artifact '$artifactId' run '$runScenarioId' reports okSampleCount+failedSampleCount=$($runOkSamples + $runFailedSamples), expected samples=$matrixExpectedSamples."
                        $artifactValidationOk = $false
                    }

                    $matrixWeakInputSampleCount += [int](Get-NumericValueOrDefault (Get-JsonValue $matrixRun "nr5WeakInputSampleCount"))
                    $matrixWeakRecoveredSampleCount += [int](Get-NumericValueOrDefault (Get-JsonValue $matrixRun "nr5WeakRecoveredSampleCount"))
                    $matrixWeakDropoutSampleCount += [int](Get-NumericValueOrDefault (Get-JsonValue $matrixRun "nr5WeakDropoutSampleCount"))
                    $matrixHotMakeupSampleCount += [int](Get-NumericValueOrDefault (Get-JsonValue $matrixRun "nr5HotMakeupSampleCount"))
                    $runWeakInput = [int](Get-NumericValueOrDefault (Get-JsonValue $matrixRun "nr5WeakInputSampleCount"))
                    $runStrongInput = [int](Get-NumericValueOrDefault (Get-JsonValue $matrixRun "nr5StrongInputSampleCount"))
                    $matrixStrongInputSampleCount += $runStrongInput
                    if ($runWeakInput -gt 0 -and $runStrongInput -gt 0) {
                        $matrixMixedWeakStrongTraceCount++
                    }
                    else {
                        $matrixMixedWeakStrongMissingRunCount++
                    }
                    if (Test-Truthy (Get-JsonValue $matrixRun "nr5WeakStrongOutputParityReady")) {
                        $matrixMixedWeakStrongReadyTraceCount++
                    }
                    $runMixedStatus = [string](Get-JsonValue $matrixRun "nr5MixedWeakStrongEvidenceStatus")
                    if ([string]::IsNullOrWhiteSpace($runMixedStatus)) {
                        $runMixedStatus = "not-evaluated"
                    }
                    if ([string]::Equals($runMixedStatus, "weak-strong-output-gap-watch", [StringComparison]::OrdinalIgnoreCase)) {
                        $matrixMixedWeakStrongGapWatchRunCount++
                    }
                    if (-not $matrixMixedWeakStrongStatusCounts.ContainsKey($runMixedStatus)) {
                        $matrixMixedWeakStrongStatusCounts[$runMixedStatus] = 0
                    }
                    $matrixMixedWeakStrongStatusCounts[$runMixedStatus] = [int]$matrixMixedWeakStrongStatusCounts[$runMixedStatus] + 1

                    $runArtifactStatus = [string](Get-JsonValue $matrixRun "nr5ArtifactRiskStatus")
                    if ([string]::IsNullOrWhiteSpace($runArtifactStatus)) {
                        $runArtifactStatus = "not-evaluated"
                    }
                    if (-not $matrixArtifactRiskStatusCounts.ContainsKey($runArtifactStatus)) {
                        $matrixArtifactRiskStatusCounts[$runArtifactStatus] = 0
                    }
                    $matrixArtifactRiskStatusCounts[$runArtifactStatus] = [int]$matrixArtifactRiskStatusCounts[$runArtifactStatus] + 1
                    if ([string]::Equals($runArtifactStatus, "artifact-review", [StringComparison]::OrdinalIgnoreCase)) {
                        $matrixArtifactReviewRunCount++
                    }
                    $runArtifactRiskScore = Get-NumericValue (Get-JsonValue $matrixRun "nr5ArtifactRiskScore")
                    if ($null -ne $runArtifactRiskScore) {
                        $matrixArtifactRiskScoreMax = [Math]::Max([double]$matrixArtifactRiskScoreMax, [double]$runArtifactRiskScore)
                    }
                    $matrixLowEvidenceLiftedSampleCount += [int](Get-NumericValueOrDefault (Get-JsonValue $matrixRun "nr5LowEvidenceLiftedSampleCount"))
                    $runLowEvidenceLiftedPct = Get-NumericValue (Get-JsonValue $matrixRun "nr5LowEvidenceLiftedPct")
                    if ($null -ne $runLowEvidenceLiftedPct) {
                        if ($null -eq $matrixLowEvidenceLiftedPctMax) {
                            $matrixLowEvidenceLiftedPctMax = [double]$runLowEvidenceLiftedPct
                        }
                        else {
                            $matrixLowEvidenceLiftedPctMax = [Math]::Max([double]$matrixLowEvidenceLiftedPctMax, [double]$runLowEvidenceLiftedPct)
                        }
                    }
                    $runAudioAlignmentMismatchPct = Get-NumericValue (Get-JsonValue $matrixRun "nr5AudioAlignmentMismatchPct")
                    if ($null -ne $runAudioAlignmentMismatchPct) {
                        if ($null -eq $matrixAudioAlignmentMismatchPctMax) {
                            $matrixAudioAlignmentMismatchPctMax = [double]$runAudioAlignmentMismatchPct
                        }
                        else {
                            $matrixAudioAlignmentMismatchPctMax = [Math]::Max([double]$matrixAudioAlignmentMismatchPctMax, [double]$runAudioAlignmentMismatchPct)
                        }
                    }
                }

                $matrixScenarioCount = @($matrixScenarioIds.ToArray() | Select-Object -Unique).Count
                $reportedMatrixScenarioCount = [int](Get-NumericValueOrDefault (Get-JsonValue $artifactJson "scenarioCount"))
                $reportedMatrixFailedRunCount = [int](Get-NumericValueOrDefault (Get-JsonValue $artifactJson "failedRunCount"))
                $reportedMatrixNotReadyTraceCount = [int](Get-NumericValueOrDefault (Get-JsonValue $artifactJson "notReadyTraceCount"))
                $reportedMatrixHardBlockerRunCount = [int](Get-NumericValueOrDefault (Get-JsonValue $artifactJson "hardBlockerRunCount"))
                $reportedMatrixHardGatePassRunCount = Get-NumericValue (Get-JsonValue $artifactJson "hardGatePassRunCount")
                $reportedMatrixStrictPreflightPassRunCount = Get-NumericValue (Get-JsonValue $artifactJson "strictPreflightPassRunCount")
                $expectedMatrixCaptureReadinessStatusCounts = @(foreach ($entry in @($matrixCaptureReadinessStatusCounts.GetEnumerator() | Sort-Object Name)) { [ordered]@{ name = [string]$entry.Key; count = [int]$entry.Value } })
                $expectedMatrixTopCaptureConstraintRunCounts = @(foreach ($entry in @($matrixTopCaptureConstraintRunCounts.GetEnumerator() | Sort-Object Name)) { [ordered]@{ name = [string]$entry.Key; count = [int]$entry.Value } })
                $expectedMatrixTopCaptureHardConstraintRunCounts = @(foreach ($entry in @($matrixTopCaptureHardConstraintRunCounts.GetEnumerator() | Sort-Object Name)) { [ordered]@{ name = [string]$entry.Key; count = [int]$entry.Value } })
                $expectedMatrixTopCaptureStatusRunCounts = @(foreach ($entry in @($matrixTopCaptureStatusRunCounts.GetEnumerator() | Sort-Object Name)) { [ordered]@{ name = [string]$entry.Key; count = [int]$entry.Value } })
                $expectedMatrixTopCaptureConstraintSampleCounts = @(foreach ($entry in @($matrixTopCaptureConstraintSampleCounts.GetEnumerator() | Sort-Object Name)) { [ordered]@{ name = [string]$entry.Key; count = [int]$entry.Value } })
                $expectedMatrixTopCaptureHardConstraintSampleCounts = @(foreach ($entry in @($matrixTopCaptureHardConstraintSampleCounts.GetEnumerator() | Sort-Object Name)) { [ordered]@{ name = [string]$entry.Key; count = [int]$entry.Value } })
                $expectedMatrixComparisonStateStatusCounts = @(foreach ($entry in @($matrixComparisonStateStatusCounts.GetEnumerator() | Sort-Object Name)) { [ordered]@{ name = [string]$entry.Key; count = [int]$entry.Value } })
                $expectedMatrixMixedWeakStrongStatusCounts = @(foreach ($entry in @($matrixMixedWeakStrongStatusCounts.GetEnumerator() | Sort-Object Name)) { [ordered]@{ name = [string]$entry.Key; count = [int]$entry.Value } })
                $expectedMatrixArtifactRiskStatusCounts = @(foreach ($entry in @($matrixArtifactRiskStatusCounts.GetEnumerator() | Sort-Object Name)) { [ordered]@{ name = [string]$entry.Key; count = [int]$entry.Value } })
                $liveMatrixMixedWeakStrongEvidence["present"] = $true
                $liveMatrixMixedWeakStrongEvidence["reportCount"] = [int]$liveMatrixMixedWeakStrongEvidence["reportCount"] + 1
                $liveMatrixArtifactControlEvidence["present"] = $true
                $liveMatrixArtifactControlEvidence["reportCount"] = [int]$liveMatrixArtifactControlEvidence["reportCount"] + 1
                if ($matrixSchemaVersion -ge 2) {
                    $liveMatrixMixedWeakStrongEvidence["schemaV2ReportCount"] = [int]$liveMatrixMixedWeakStrongEvidence["schemaV2ReportCount"] + 1
                    $liveMatrixMixedWeakStrongEvidence["traceCount"] = [int]$liveMatrixMixedWeakStrongEvidence["traceCount"] + $matrixMixedWeakStrongTraceCount
                    $liveMatrixMixedWeakStrongEvidence["readyTraceCount"] = [int]$liveMatrixMixedWeakStrongEvidence["readyTraceCount"] + $matrixMixedWeakStrongReadyTraceCount
                    $liveMatrixMixedWeakStrongEvidence["missingRunCount"] = [int]$liveMatrixMixedWeakStrongEvidence["missingRunCount"] + $matrixMixedWeakStrongMissingRunCount
                    $liveMatrixMixedWeakStrongEvidence["gapWatchRunCount"] = [int]$liveMatrixMixedWeakStrongEvidence["gapWatchRunCount"] + $matrixMixedWeakStrongGapWatchRunCount
                    $liveMatrixMixedWeakStrongEvidence["weakInputSampleCount"] = [int]$liveMatrixMixedWeakStrongEvidence["weakInputSampleCount"] + $matrixWeakInputSampleCount
                    $liveMatrixMixedWeakStrongEvidence["strongInputSampleCount"] = [int]$liveMatrixMixedWeakStrongEvidence["strongInputSampleCount"] + $matrixStrongInputSampleCount
                    if ($matrixMixedWeakStrongReadyTraceCount -gt 0) {
                        $liveMatrixMixedWeakStrongEvidence["huntReady"] = $true
                        $liveMatrixMixedWeakStrongEvidence["readyReportCount"] = [int]$liveMatrixMixedWeakStrongEvidence["readyReportCount"] + 1
                    }
                    foreach ($statusEntry in @($expectedMatrixMixedWeakStrongStatusCounts)) {
                        $statusName = [string](Get-JsonValue $statusEntry "name")
                        $statusCount = [int](Get-NumericValueOrDefault (Get-JsonValue $statusEntry "count"))
                        if ([string]::IsNullOrWhiteSpace($statusName) -or $statusCount -le 0) {
                            continue
                        }
                        if (-not $liveMatrixMixedWeakStrongStatusCountMap.ContainsKey($statusName)) {
                            $liveMatrixMixedWeakStrongStatusCountMap[$statusName] = 0
                        }
                        $liveMatrixMixedWeakStrongStatusCountMap[$statusName] = [int]$liveMatrixMixedWeakStrongStatusCountMap[$statusName] + $statusCount
                    }

                    $reportedBestRun = Get-JsonValue $artifactJson "bestMixedWeakStrongRun"
                    $reportedBestScore = Get-NumericValue (Get-JsonValue $reportedBestRun "nr5MixedWeakStrongHuntScore")
                    if ($null -ne $reportedBestRun -and $null -ne $reportedBestScore -and
                        ($null -eq $liveMatrixMixedWeakStrongBestScore -or [double]$reportedBestScore -gt [double]$liveMatrixMixedWeakStrongBestScore)) {
                        $liveMatrixMixedWeakStrongBestScore = [double]$reportedBestScore
                        $liveMatrixMixedWeakStrongEvidence["bestRun"] = [ordered]@{
                            artifactId = $artifactId
                            artifactPath = $artifactPath
                            scenarioId = [string](Get-JsonValue $reportedBestRun "scenarioId")
                            comparisonId = [string](Get-JsonValue $reportedBestRun "comparisonId")
                            reportPath = [string](Get-JsonValue $reportedBestRun "reportPath")
                            readyForBenchmarkTrace = Test-Truthy (Get-JsonValue $reportedBestRun "readyForBenchmarkTrace")
                            weakInputSampleCount = [int](Get-NumericValueOrDefault (Get-JsonValue $reportedBestRun "nr5WeakInputSampleCount"))
                            strongInputSampleCount = [int](Get-NumericValueOrDefault (Get-JsonValue $reportedBestRun "nr5StrongInputSampleCount"))
                            weakStrongOutputGapDb = Get-NumericValue (Get-JsonValue $reportedBestRun "nr5WeakStrongOutputGapDb")
                            mixedWeakStrongEvidenceStatus = [string](Get-JsonValue $reportedBestRun "nr5MixedWeakStrongEvidenceStatus")
                            mixedWeakStrongHuntScore = [double]$reportedBestScore
                        }
                    }
                }
                if ($matrixSchemaVersion -ge 3) {
                    $liveMatrixArtifactControlEvidence["schemaV3ReportCount"] = [int]$liveMatrixArtifactControlEvidence["schemaV3ReportCount"] + 1
                    $liveMatrixArtifactControlEvidence["artifactReviewRunCount"] = [int]$liveMatrixArtifactControlEvidence["artifactReviewRunCount"] + $matrixArtifactReviewRunCount
                    $liveMatrixArtifactControlEvidence["artifactRiskScoreMax"] = [Math]::Max([double]$liveMatrixArtifactControlEvidence["artifactRiskScoreMax"], [double]$matrixArtifactRiskScoreMax)
                    $liveMatrixArtifactControlEvidence["lowEvidenceLiftedSampleCount"] = [int]$liveMatrixArtifactControlEvidence["lowEvidenceLiftedSampleCount"] + $matrixLowEvidenceLiftedSampleCount
                    if ($null -ne $matrixLowEvidenceLiftedPctMax) {
                        if ($null -eq $liveMatrixArtifactControlEvidence["lowEvidenceLiftedPctMax"]) {
                            $liveMatrixArtifactControlEvidence["lowEvidenceLiftedPctMax"] = [double]$matrixLowEvidenceLiftedPctMax
                        }
                        else {
                            $liveMatrixArtifactControlEvidence["lowEvidenceLiftedPctMax"] = [Math]::Max([double]$liveMatrixArtifactControlEvidence["lowEvidenceLiftedPctMax"], [double]$matrixLowEvidenceLiftedPctMax)
                        }
                    }
                    if ($null -ne $matrixAudioAlignmentMismatchPctMax) {
                        if ($null -eq $liveMatrixArtifactControlEvidence["audioAlignmentMismatchPctMax"]) {
                            $liveMatrixArtifactControlEvidence["audioAlignmentMismatchPctMax"] = [double]$matrixAudioAlignmentMismatchPctMax
                        }
                        else {
                            $liveMatrixArtifactControlEvidence["audioAlignmentMismatchPctMax"] = [Math]::Max([double]$liveMatrixArtifactControlEvidence["audioAlignmentMismatchPctMax"], [double]$matrixAudioAlignmentMismatchPctMax)
                        }
                    }
                    foreach ($statusEntry in @($expectedMatrixArtifactRiskStatusCounts)) {
                        $statusName = [string](Get-JsonValue $statusEntry "name")
                        $statusCount = [int](Get-NumericValueOrDefault (Get-JsonValue $statusEntry "count"))
                        if ([string]::IsNullOrWhiteSpace($statusName) -or $statusCount -le 0) {
                            continue
                        }
                        if (-not $liveMatrixArtifactControlStatusCountMap.ContainsKey($statusName)) {
                            $liveMatrixArtifactControlStatusCountMap[$statusName] = 0
                        }
                        $liveMatrixArtifactControlStatusCountMap[$statusName] = [int]$liveMatrixArtifactControlStatusCountMap[$statusName] + $statusCount
                    }
                }

                if ($reportedMatrixScenarioCount -ne $matrixScenarioCount) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-scenario-count-mismatch" "Artifact '$artifactId' reports scenarioCount=$reportedMatrixScenarioCount but runs cover $matrixScenarioCount scenario(s)."
                    $artifactValidationOk = $false
                }
                if ($reportedMatrixFailedRunCount -ne $matrixFailedRunCount) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-failed-count-mismatch" "Artifact '$artifactId' reports failedRunCount=$reportedMatrixFailedRunCount but runs contain $matrixFailedRunCount failed run(s)."
                    $artifactValidationOk = $false
                }
                if ($reportedMatrixNotReadyTraceCount -ne $matrixNotReadyTraceCount) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-not-ready-count-mismatch" "Artifact '$artifactId' reports notReadyTraceCount=$reportedMatrixNotReadyTraceCount but runs contain $matrixNotReadyTraceCount not-ready trace(s)."
                    $artifactValidationOk = $false
                }
                if ($reportedMatrixHardBlockerRunCount -ne $matrixHardBlockerRunCount) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-hard-blocker-count-mismatch" "Artifact '$artifactId' reports hardBlockerRunCount=$reportedMatrixHardBlockerRunCount but runs contain $matrixHardBlockerRunCount hard-blocker run(s)."
                    $artifactValidationOk = $false
                }
                if ($null -ne $reportedMatrixHardGatePassRunCount -and [int]$reportedMatrixHardGatePassRunCount -ne $matrixHardGatePassRunCount) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-capture-readiness-count-mismatch" "Artifact '$artifactId' reports hardGatePassRunCount=$([int]$reportedMatrixHardGatePassRunCount) but runs contain $matrixHardGatePassRunCount hard-gate pass run(s)."
                    $artifactValidationOk = $false
                }
                if ($null -ne $reportedMatrixStrictPreflightPassRunCount -and [int]$reportedMatrixStrictPreflightPassRunCount -ne $matrixStrictPreflightPassRunCount) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-capture-readiness-count-mismatch" "Artifact '$artifactId' reports strictPreflightPassRunCount=$([int]$reportedMatrixStrictPreflightPassRunCount) but runs contain $matrixStrictPreflightPassRunCount strict-preflight pass run(s)."
                    $artifactValidationOk = $false
                }
                $reportedMatrixComparisonStateStrictRunCount = Get-NumericValue (Get-JsonValue $artifactJson "comparisonStateStrictRunCount")
                $reportedMatrixComparisonStateReadyRunCount = Get-NumericValue (Get-JsonValue $artifactJson "comparisonStateReadyRunCount")
                $reportedMatrixComparisonStateStrictFailureCount = Get-NumericValue (Get-JsonValue $artifactJson "comparisonStateStrictFailureCount")
                if ($null -ne $reportedMatrixComparisonStateStrictRunCount -and [int]$reportedMatrixComparisonStateStrictRunCount -ne $matrixComparisonStateStrictRunCount) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-comparison-state-count-mismatch" "Artifact '$artifactId' reports comparisonStateStrictRunCount=$([int]$reportedMatrixComparisonStateStrictRunCount) but runs contain $matrixComparisonStateStrictRunCount strict state run(s)."
                    $artifactValidationOk = $false
                }
                if ($null -ne $reportedMatrixComparisonStateReadyRunCount -and [int]$reportedMatrixComparisonStateReadyRunCount -ne $matrixComparisonStateReadyRunCount) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-comparison-state-count-mismatch" "Artifact '$artifactId' reports comparisonStateReadyRunCount=$([int]$reportedMatrixComparisonStateReadyRunCount) but runs contain $matrixComparisonStateReadyRunCount state-ready run(s)."
                    $artifactValidationOk = $false
                }
                if ($null -ne $reportedMatrixComparisonStateStrictFailureCount -and [int]$reportedMatrixComparisonStateStrictFailureCount -ne $matrixComparisonStateStrictFailureCount) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-comparison-state-count-mismatch" "Artifact '$artifactId' reports comparisonStateStrictFailureCount=$([int]$reportedMatrixComparisonStateStrictFailureCount) but runs contain $matrixComparisonStateStrictFailureCount strict state failure(s)."
                    $artifactValidationOk = $false
                }
                foreach ($captureCountSpec in @(
                        @{ Name = "captureReadinessStatusCounts"; Expected = $expectedMatrixCaptureReadinessStatusCounts },
                        @{ Name = "comparisonStateStatusCounts"; Expected = $expectedMatrixComparisonStateStatusCounts },
                        @{ Name = "topCaptureConstraintRunCounts"; Expected = $expectedMatrixTopCaptureConstraintRunCounts },
                        @{ Name = "topCaptureHardConstraintRunCounts"; Expected = $expectedMatrixTopCaptureHardConstraintRunCounts },
                        @{ Name = "topCaptureStatusRunCounts"; Expected = $expectedMatrixTopCaptureStatusRunCounts },
                        @{ Name = "topCaptureConstraintSampleCounts"; Expected = $expectedMatrixTopCaptureConstraintSampleCounts },
                        @{ Name = "topCaptureHardConstraintSampleCounts"; Expected = $expectedMatrixTopCaptureHardConstraintSampleCounts }
                    )) {
                    $countName = [string]$captureCountSpec["Name"]
                    $actualCounts = @(Get-JsonArray $artifactJson $countName)
                    if ($actualCounts.Count -eq 0) {
                        continue
                    }
                    if (-not (Test-LiveHistoryNamedCountsMatch -Actual $actualCounts -Expected @($captureCountSpec["Expected"]))) {
                        Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-capture-readiness-count-mismatch" "Artifact '$artifactId' $countName does not match the runs[] capture-readiness rollup."
                        $artifactValidationOk = $false
                    }
                }

                $expectedMatrixCollectionReady = ($matrixFailedRunCount -eq 0)
                $expectedMatrixAcceptanceReady = ($matrixFailedRunCount -eq 0 -and $matrixNotReadyTraceCount -eq 0 -and $matrixHardBlockerRunCount -eq 0 -and $matrixComparisonStateStrictFailureCount -eq 0)
                if ((Test-Truthy (Get-JsonValue $artifactJson "collectionReady")) -ne $expectedMatrixCollectionReady) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-collection-ready-mismatch" "Artifact '$artifactId' collectionReady does not match failedRunCount."
                    $artifactValidationOk = $false
                }
                if ((Test-Truthy (Get-JsonValue $artifactJson "acceptanceReady")) -ne $expectedMatrixAcceptanceReady) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-acceptance-ready-mismatch" "Artifact '$artifactId' acceptanceReady does not match failed/not-ready/hard-blocker/comparison-state counts."
                    $artifactValidationOk = $false
                }
                if ($matrixComparisonStateStrictFailureCount -gt 0) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-comparison-state-not-ready" "Artifact '$artifactId' has $matrixComparisonStateStrictFailureCount strict comparison-state failure run(s)."
                    $artifactValidationOk = $false
                }

                foreach ($counterSpec in @(
                        @{ Name = "nr5WeakInputSampleCount"; Expected = $matrixWeakInputSampleCount },
                        @{ Name = "nr5WeakRecoveredSampleCount"; Expected = $matrixWeakRecoveredSampleCount },
                        @{ Name = "nr5WeakDropoutSampleCount"; Expected = $matrixWeakDropoutSampleCount },
                        @{ Name = "nr5HotMakeupSampleCount"; Expected = $matrixHotMakeupSampleCount }
                    )) {
                    $counterName = [string]$counterSpec["Name"]
                    $reportedCounter = [int](Get-NumericValueOrDefault (Get-JsonValue $artifactJson $counterName))
                    $expectedCounter = [int]$counterSpec["Expected"]
                    if ($reportedCounter -ne $expectedCounter) {
                        Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-weak-counter-mismatch" "Artifact '$artifactId' reports $counterName=$reportedCounter but runs sum to $expectedCounter."
                        $artifactValidationOk = $false
                    }
                }

                if ($matrixSchemaVersion -ge 2) {
                    foreach ($mixedCounterSpec in @(
                            @{ Name = "nr5StrongInputSampleCount"; Expected = $matrixStrongInputSampleCount },
                            @{ Name = "nr5MixedWeakStrongTraceCount"; Expected = $matrixMixedWeakStrongTraceCount },
                            @{ Name = "nr5MixedWeakStrongReadyTraceCount"; Expected = $matrixMixedWeakStrongReadyTraceCount },
                            @{ Name = "nr5MixedWeakStrongMissingRunCount"; Expected = $matrixMixedWeakStrongMissingRunCount },
                            @{ Name = "nr5MixedWeakStrongGapWatchRunCount"; Expected = $matrixMixedWeakStrongGapWatchRunCount }
                        )) {
                        $counterName = [string]$mixedCounterSpec["Name"]
                        $reportedCounterValue = Get-NumericValue (Get-JsonValue $artifactJson $counterName)
                        $expectedCounterValue = [int]$mixedCounterSpec["Expected"]
                        if ($null -eq $reportedCounterValue -or [int]$reportedCounterValue -ne $expectedCounterValue) {
                            Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-mixed-weak-strong-count-mismatch" "Artifact '$artifactId' reports $counterName='$reportedCounterValue' but runs imply $expectedCounterValue."
                            $artifactValidationOk = $false
                        }
                    }

                    $reportedMixedHuntReady = Test-Truthy (Get-JsonValue $artifactJson "nr5MixedWeakStrongHuntReady")
                    $expectedMixedHuntReady = ($matrixMixedWeakStrongReadyTraceCount -gt 0)
                    if ($reportedMixedHuntReady -ne $expectedMixedHuntReady) {
                        Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-mixed-weak-strong-ready-mismatch" "Artifact '$artifactId' nr5MixedWeakStrongHuntReady=$reportedMixedHuntReady but runs imply $expectedMixedHuntReady."
                        $artifactValidationOk = $false
                    }

                    $reportedMixedStatusCounts = @(Get-JsonArray $artifactJson "nr5MixedWeakStrongStatusCounts")
                    if (-not (Test-LiveHistoryNamedCountsMatch -Actual $reportedMixedStatusCounts -Expected $expectedMatrixMixedWeakStrongStatusCounts)) {
                        Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-mixed-weak-strong-status-count-mismatch" "Artifact '$artifactId' nr5MixedWeakStrongStatusCounts does not match runs[]."
                        $artifactValidationOk = $false
                    }
                }

                if ($matrixSchemaVersion -ge 3) {
                    foreach ($artifactCounterSpec in @(
                            @{ Name = "nr5ArtifactReviewRunCount"; Expected = $matrixArtifactReviewRunCount },
                            @{ Name = "nr5LowEvidenceLiftedSampleCount"; Expected = $matrixLowEvidenceLiftedSampleCount }
                        )) {
                        $counterName = [string]$artifactCounterSpec["Name"]
                        $reportedCounterValue = Get-NumericValue (Get-JsonValue $artifactJson $counterName)
                        $expectedCounterValue = [int]$artifactCounterSpec["Expected"]
                        if ($null -eq $reportedCounterValue -or [int]$reportedCounterValue -ne $expectedCounterValue) {
                            Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-artifact-control-count-mismatch" "Artifact '$artifactId' reports $counterName='$reportedCounterValue' but runs imply $expectedCounterValue."
                            $artifactValidationOk = $false
                        }
                    }

                    foreach ($artifactScalarSpec in @(
                            @{ Name = "nr5ArtifactRiskScoreMax"; Expected = $matrixArtifactRiskScoreMax },
                            @{ Name = "nr5LowEvidenceLiftedPctMax"; Expected = $matrixLowEvidenceLiftedPctMax },
                            @{ Name = "nr5AudioAlignmentMismatchPctMax"; Expected = $matrixAudioAlignmentMismatchPctMax }
                        )) {
                        $fieldName = [string]$artifactScalarSpec["Name"]
                        $reportedScalar = Get-NumericValue (Get-JsonValue $artifactJson $fieldName)
                        $expectedScalar = $artifactScalarSpec["Expected"]
                        if ($null -eq $reportedScalar -and $null -eq $expectedScalar) {
                            continue
                        }
                        if ($null -eq $reportedScalar -or -not (Test-NumericClose -Actual $reportedScalar -Expected $expectedScalar)) {
                            Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-artifact-control-scalar-mismatch" "Artifact '$artifactId' reports $fieldName='$reportedScalar' but runs imply '$expectedScalar'."
                            $artifactValidationOk = $false
                        }
                    }

                    $reportedArtifactStatusCounts = @(Get-JsonArray $artifactJson "nr5ArtifactRiskStatusCounts")
                    if (-not (Test-LiveHistoryNamedCountsMatch -Actual $reportedArtifactStatusCounts -Expected $expectedMatrixArtifactRiskStatusCounts)) {
                        Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-artifact-control-status-count-mismatch" "Artifact '$artifactId' nr5ArtifactRiskStatusCounts does not match runs[]."
                        $artifactValidationOk = $false
                    }
                }

                $matrixIndexPath = [string](Get-JsonValue $artifactJson "indexPath")
                if ([string]::IsNullOrWhiteSpace($matrixIndexPath)) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-index-path-missing" "Artifact '$artifactId' does not declare indexPath."
                    $artifactValidationOk = $false
                }
                else {
                    if ([System.IO.Path]::IsPathRooted($matrixIndexPath)) {
                        Add-ValidationIssue $warnings "warning" "live-matrix-report-index-path-absolute" "Artifact '$artifactId' uses an absolute indexPath; relative paths keep capture bundles portable."
                    }

                    $resolvedMatrixIndexPath = Get-BundlePath $bundlePath $matrixIndexPath
                    if (-not (Test-Path -LiteralPath $resolvedMatrixIndexPath -PathType Leaf)) {
                        Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-index-file-missing" "Artifact '$artifactId' references a missing trace index: $matrixIndexPath"
                        $artifactValidationOk = $false
                    }
                    else {
                        $matrixIndexSha256 = [string](Get-JsonValue $artifactJson "indexSha256")
                        if (-not [string]::IsNullOrWhiteSpace($matrixIndexSha256)) {
                            $actualMatrixIndexSha256 = Get-FileSha256 $resolvedMatrixIndexPath
                            if (-not [string]::Equals($matrixIndexSha256.Trim().ToLowerInvariant(), $actualMatrixIndexSha256, [StringComparison]::OrdinalIgnoreCase)) {
                                Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-index-hash-mismatch" "Artifact '$artifactId' reports indexSha256='$matrixIndexSha256' but '$matrixIndexPath' hashes to '$actualMatrixIndexSha256'."
                                $artifactValidationOk = $false
                            }
                        }

                        $matrixIndexJson = $null
                        try {
                            $matrixIndexJson = Read-JsonFile $resolvedMatrixIndexPath
                        }
                        catch {
                            Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-index-json-invalid" $_.Exception.Message
                            $artifactValidationOk = $false
                        }

                        if ($null -ne $matrixIndexJson) {
                            $matrixIndexSchemaVersion = [int](Get-NumericValueOrDefault (Get-JsonValue $matrixIndexJson "schemaVersion"))
                            $matrixIndexEntries = @(Get-JsonArray $matrixIndexJson "files")
                            foreach ($matrixRun in $matrixRuns) {
                                $runScenarioId = ConvertTo-LiveHistoryScenarioId ([string](Get-JsonValue $matrixRun "scenarioId"))
                                $runComparisonId = ConvertTo-ComparisonId ([string](Get-JsonValue $matrixRun "comparisonId"))
                                $runLabel = if (-not [string]::IsNullOrWhiteSpace($runScenarioId) -and -not [string]::IsNullOrWhiteSpace($runComparisonId)) { "$runScenarioId/$runComparisonId" } else { "unknown-run" }
                                $matchingIndexEntries = @($matrixIndexEntries | Where-Object {
                                        $entryScenarioIds = @(Get-ArtifactIndexFileScenarioIds $_ | ForEach-Object { ConvertTo-LiveHistoryScenarioId ([string]$_) })
                                        $entryComparisonIds = @(Get-ArtifactIndexFileExplicitComparisonIds $_)
                                        (Test-StringArrayContains $entryScenarioIds $runScenarioId) -and
                                        (Test-StringArrayContains $entryComparisonIds $runComparisonId)
                                    })

                                if ($matchingIndexEntries.Count -eq 0) {
                                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-run-index-entry-missing" "Artifact '$artifactId' run '$runLabel' has no matching trace-index entry in '$matrixIndexPath'."
                                    $artifactValidationOk = $false
                                    continue
                                }
                                if ($matchingIndexEntries.Count -gt 1) {
                                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-run-index-entry-ambiguous" "Artifact '$artifactId' run '$runLabel' matches $($matchingIndexEntries.Count) trace-index entries in '$matrixIndexPath'."
                                    $artifactValidationOk = $false
                                    continue
                                }

                                $matchingIndexEntry = $matchingIndexEntries[0]
                                $indexJsonlPath = Get-ArtifactIndexFilePath $matchingIndexEntry
                                $runJsonlPath = [string](Get-JsonValue $matrixRun "jsonlPath")
                                if ([string]::IsNullOrWhiteSpace($indexJsonlPath) -or [string]::IsNullOrWhiteSpace($runJsonlPath) -or -not (Test-ComparableEvidencePathSame -BundlePath $bundlePath -ExpectedPath $indexJsonlPath -ActualPath $runJsonlPath)) {
                                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-run-jsonl-path-mismatch" "Artifact '$artifactId' run '$runLabel' jsonlPath='$runJsonlPath' does not match trace-index path='$indexJsonlPath'."
                                    $artifactValidationOk = $false
                                }

                                $indexSummaryPath = Get-ArtifactIndexFileSummaryPath $matchingIndexEntry
                                $runReportPath = [string](Get-JsonValue $matrixRun "reportPath")
                                if ([string]::IsNullOrWhiteSpace($indexSummaryPath) -or [string]::IsNullOrWhiteSpace($runReportPath) -or -not (Test-ComparableEvidencePathSame -BundlePath $bundlePath -ExpectedPath $indexSummaryPath -ActualPath $runReportPath)) {
                                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-run-summary-path-mismatch" "Artifact '$artifactId' run '$runLabel' reportPath='$runReportPath' does not match trace-index summaryPath='$indexSummaryPath'."
                                    $artifactValidationOk = $false
                                }

                                $indexSampleCount = Get-NumericValue (Get-JsonValue $matchingIndexEntry "sampleCount")
                                $runOkSamples = [int](Get-NumericValueOrDefault (Get-JsonValue $matrixRun "okSampleCount"))
                                $runFailedSamples = [int](Get-NumericValueOrDefault (Get-JsonValue $matrixRun "failedSampleCount"))
                                if ($null -eq $indexSampleCount) {
                                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-run-index-sample-count-missing" "Artifact '$artifactId' run '$runLabel' matched a trace-index entry without sampleCount."
                                    $artifactValidationOk = $false
                                }
                                else {
                                    if (($runOkSamples + $runFailedSamples) -ne [int]$indexSampleCount) {
                                        Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-run-index-sample-count-mismatch" "Artifact '$artifactId' run '$runLabel' reports okSampleCount+failedSampleCount=$($runOkSamples + $runFailedSamples) but trace-index sampleCount=$([int]$indexSampleCount)."
                                        $artifactValidationOk = $false
                                    }
                                }

                                $runCaptureReadinessStatus = [string](Get-JsonValue $matrixRun "captureReadinessStatus")
                                $indexCaptureReadinessStatus = [string](Get-JsonValue $matchingIndexEntry "captureReadinessStatus")
                                if (-not [string]::IsNullOrWhiteSpace($runCaptureReadinessStatus) -and
                                    -not [string]::IsNullOrWhiteSpace($indexCaptureReadinessStatus) -and
                                    -not [string]::Equals($runCaptureReadinessStatus, $indexCaptureReadinessStatus, [StringComparison]::OrdinalIgnoreCase)) {
                                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-run-index-capture-readiness-mismatch" "Artifact '$artifactId' run '$runLabel' captureReadinessStatus='$runCaptureReadinessStatus' but trace-index entry reports '$indexCaptureReadinessStatus'."
                                    $artifactValidationOk = $false
                                }

                                foreach ($readinessBoolSpec in @("hardGatePass", "strictPreflightPass")) {
                                    $runValue = Get-JsonValue $matrixRun $readinessBoolSpec
                                    $indexValue = Get-JsonValue $matchingIndexEntry $readinessBoolSpec
                                    if ($null -ne $runValue -and $null -ne $indexValue -and (Test-Truthy $runValue) -ne (Test-Truthy $indexValue)) {
                                        Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-run-index-capture-readiness-mismatch" "Artifact '$artifactId' run '$runLabel' $readinessBoolSpec='$runValue' but trace-index entry reports '$indexValue'."
                                        $artifactValidationOk = $false
                                    }
                                }

                                foreach ($readinessFieldSpec in @(
                                        @{ Name = "topCaptureConstraintName"; Kind = "text" },
                                        @{ Name = "topCaptureHardConstraintName"; Kind = "text" },
                                        @{ Name = "topCaptureStatusName"; Kind = "text" },
                                        @{ Name = "topCaptureConstraintCount"; Kind = "number" },
                                        @{ Name = "topCaptureHardConstraintCount"; Kind = "number" },
                                        @{ Name = "topCaptureStatusCount"; Kind = "number" }
                                    )) {
                                    $fieldName = [string]$readinessFieldSpec["Name"]
                                    $kind = [string]$readinessFieldSpec["Kind"]
                                    if ($kind -eq "text") {
                                        $runValue = [string](Get-JsonValue $matrixRun $fieldName)
                                        $indexValue = [string](Get-JsonValue $matchingIndexEntry $fieldName)
                                        if (-not [string]::IsNullOrWhiteSpace($runValue) -and
                                            -not [string]::IsNullOrWhiteSpace($indexValue) -and
                                            -not [string]::Equals($runValue, $indexValue, [StringComparison]::OrdinalIgnoreCase)) {
                                            Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-run-index-capture-readiness-mismatch" "Artifact '$artifactId' run '$runLabel' $fieldName='$runValue' but trace-index entry reports '$indexValue'."
                                            $artifactValidationOk = $false
                                        }
                                    }
                                    else {
                                        $runValue = Get-NumericValue (Get-JsonValue $matrixRun $fieldName)
                                        $indexValue = Get-NumericValue (Get-JsonValue $matchingIndexEntry $fieldName)
                                        if ($null -ne $runValue -and $null -ne $indexValue -and [int]$runValue -ne [int]$indexValue) {
                                            Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-run-index-capture-readiness-mismatch" "Artifact '$artifactId' run '$runLabel' $fieldName=$([int]$runValue) but trace-index entry reports $([int]$indexValue)."
                                            $artifactValidationOk = $false
                                        }
                                    }
                                }

                                foreach ($counterSpec in @(
                                        @{ Name = "nr5WeakInputSampleCount" },
                                        @{ Name = "nr5WeakRecoveredSampleCount" },
                                        @{ Name = "nr5WeakDropoutSampleCount" },
                                        @{ Name = "nr5HotMakeupSampleCount" }
                                    )) {
                                    $counterName = [string]$counterSpec["Name"]
                                    $indexCounterValue = Get-NumericValue (Get-JsonValue $matchingIndexEntry $counterName)
                                    if ($null -eq $indexCounterValue) {
                                        Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-run-index-weak-counter-missing" "Artifact '$artifactId' run '$runLabel' matched a trace-index entry without $counterName."
                                        $artifactValidationOk = $false
                                        continue
                                    }

                                    $runCounterValue = [int](Get-NumericValueOrDefault (Get-JsonValue $matrixRun $counterName))
                                    if ($runCounterValue -ne [int]$indexCounterValue) {
                                        Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-run-index-weak-counter-mismatch" "Artifact '$artifactId' run '$runLabel' reports $counterName=$runCounterValue but trace-index entry reports $([int]$indexCounterValue)."
                                        $artifactValidationOk = $false
                                    }
                                }

                                if ($matrixSchemaVersion -ge 2 -or $matrixIndexSchemaVersion -ge 2) {
                                    foreach ($mixedNumberSpec in @(
                                            "nr5StrongInputSampleCount",
                                            "nr5WeakStrongOutputGapDb",
                                            "nr5MixedWeakStrongHuntScore"
                                        )) {
                                        $fieldName = [string]$mixedNumberSpec
                                        $runValue = Get-NumericValue (Get-JsonValue $matrixRun $fieldName)
                                        $indexValue = Get-NumericValue (Get-JsonValue $matchingIndexEntry $fieldName)
                                        if ($null -eq $runValue -and $null -eq $indexValue) {
                                            continue
                                        }
                                        if ($null -eq $indexValue) {
                                            Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-run-index-mixed-weak-strong-missing" "Artifact '$artifactId' run '$runLabel' matched a trace-index entry without $fieldName."
                                            $artifactValidationOk = $false
                                            continue
                                        }
                                        if (-not (Test-NumericClose -Actual $indexValue -Expected $runValue)) {
                                            Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-run-index-mixed-weak-strong-mismatch" "Artifact '$artifactId' run '$runLabel' reports $fieldName='$runValue' but trace-index entry reports '$indexValue'."
                                            $artifactValidationOk = $false
                                        }
                                    }

                                    foreach ($mixedBoolSpec in @(
                                            "nr5MixedWeakStrongEvidenceReady",
                                            "nr5WeakStrongOutputParityReady"
                                        )) {
                                        $fieldName = [string]$mixedBoolSpec
                                        $runValue = Get-JsonValue $matrixRun $fieldName
                                        $indexValue = Get-JsonValue $matchingIndexEntry $fieldName
                                        if ($null -eq $indexValue) {
                                            Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-run-index-mixed-weak-strong-missing" "Artifact '$artifactId' run '$runLabel' matched a trace-index entry without $fieldName."
                                            $artifactValidationOk = $false
                                            continue
                                        }
                                        if ((Test-Truthy $runValue) -ne (Test-Truthy $indexValue)) {
                                            Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-run-index-mixed-weak-strong-mismatch" "Artifact '$artifactId' run '$runLabel' reports $fieldName='$runValue' but trace-index entry reports '$indexValue'."
                                            $artifactValidationOk = $false
                                        }
                                    }

                                    $runMixedStatus = [string](Get-JsonValue $matrixRun "nr5MixedWeakStrongEvidenceStatus")
                                    $indexMixedStatus = [string](Get-JsonValue $matchingIndexEntry "nr5MixedWeakStrongEvidenceStatus")
                                    if ([string]::IsNullOrWhiteSpace($indexMixedStatus)) {
                                        Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-run-index-mixed-weak-strong-missing" "Artifact '$artifactId' run '$runLabel' matched a trace-index entry without nr5MixedWeakStrongEvidenceStatus."
                                        $artifactValidationOk = $false
                                    }
                                    elseif (-not [string]::Equals($runMixedStatus, $indexMixedStatus, [StringComparison]::OrdinalIgnoreCase)) {
                                        Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-run-index-mixed-weak-strong-mismatch" "Artifact '$artifactId' run '$runLabel' reports nr5MixedWeakStrongEvidenceStatus='$runMixedStatus' but trace-index entry reports '$indexMixedStatus'."
                                        $artifactValidationOk = $false
                                    }
                                }

                                if ($matrixSchemaVersion -ge 3 -or $matrixIndexSchemaVersion -ge 3) {
                                    foreach ($artifactNumberSpec in @(
                                            "nr5TextureFillAverage",
                                            "nr5SignalProbabilityAverage",
                                            "nr5LowEvidenceLiftedSampleCount",
                                            "nr5LowEvidenceLiftedPct",
                                            "nr5LowEvidenceAlignmentMismatchPct",
                                            "nr5AudioAlignmentMismatchPct",
                                            "nr5ArtifactRiskScore"
                                        )) {
                                        $fieldName = [string]$artifactNumberSpec
                                        $runValue = Get-NumericValue (Get-JsonValue $matrixRun $fieldName)
                                        $indexValue = Get-NumericValue (Get-JsonValue $matchingIndexEntry $fieldName)
                                        if ($null -eq $runValue -and $null -eq $indexValue) {
                                            continue
                                        }
                                        if ($null -eq $indexValue) {
                                            Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-run-index-artifact-control-missing" "Artifact '$artifactId' run '$runLabel' matched a trace-index entry without $fieldName."
                                            $artifactValidationOk = $false
                                            continue
                                        }
                                        if (-not (Test-NumericClose -Actual $indexValue -Expected $runValue)) {
                                            Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-run-index-artifact-control-mismatch" "Artifact '$artifactId' run '$runLabel' reports $fieldName='$runValue' but trace-index entry reports '$indexValue'."
                                            $artifactValidationOk = $false
                                        }
                                    }

                                    $runArtifactStatus = [string](Get-JsonValue $matrixRun "nr5ArtifactRiskStatus")
                                    $indexArtifactStatus = [string](Get-JsonValue $matchingIndexEntry "nr5ArtifactRiskStatus")
                                    if ([string]::IsNullOrWhiteSpace($indexArtifactStatus)) {
                                        Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-run-index-artifact-control-missing" "Artifact '$artifactId' run '$runLabel' matched a trace-index entry without nr5ArtifactRiskStatus."
                                        $artifactValidationOk = $false
                                    }
                                    elseif (-not [string]::Equals($runArtifactStatus, $indexArtifactStatus, [StringComparison]::OrdinalIgnoreCase)) {
                                        Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-matrix-report-run-index-artifact-control-mismatch" "Artifact '$artifactId' run '$runLabel' reports nr5ArtifactRiskStatus='$runArtifactStatus' but trace-index entry reports '$indexArtifactStatus'."
                                        $artifactValidationOk = $false
                                    }
                                }
                            }
                        }
                    }
                }
            }

            if ($artifactKind -ieq "diagnostics-comparison-json" -or $artifactId -eq $liveTraceComparisonArtifactId -or $artifactId -eq $liveTraceThetisComparisonArtifactId) {
                $previousLiveTraceComparisonEvidence = $liveTraceComparisonEvidence
                if ($artifactId -eq $liveTraceThetisComparisonArtifactId) {
                    $liveTraceComparisonEvidence = $liveTraceThetisComparisonEvidence
                }
                $liveTraceComparisonEvidence["present"] = $true

                $tool = [string](Get-JsonValue $artifactJson "tool")
                if ($tool -ne "compare-dsp-live-diagnostics-traces" -and $tool -ne "compare-dsp-live-diagnostics-matrix") {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-tool-invalid" "Artifact '$artifactId' must be generated by compare-dsp-live-diagnostics-traces.ps1 or compare-dsp-live-diagnostics-matrix.ps1."
                    $artifactValidationOk = $false
                }

                if ($tool -eq "compare-dsp-live-diagnostics-traces") {
                    foreach ($inputSpec in @(
                            @{ Role = "baseline"; PathName = "baselinePath"; HashName = "baselineInputSha256" },
                            @{ Role = "candidate"; PathName = "candidatePath"; HashName = "candidateInputSha256" }
                        )) {
                        $role = [string]$inputSpec["Role"]
                        $inputPathName = [string]$inputSpec["PathName"]
                        $inputHashName = [string]$inputSpec["HashName"]
                        $inputPathValue = [string](Get-JsonValue $artifactJson $inputPathName)
                        if ([string]::IsNullOrWhiteSpace($inputPathValue)) {
                            Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-$role-input-path-missing" "Artifact '$artifactId' does not declare $inputPathName."
                            $artifactValidationOk = $false
                            continue
                        }

                        $resolvedInputPath = Get-BundlePath $bundlePath $inputPathValue
                        if (-not (Test-Path -LiteralPath $resolvedInputPath -PathType Leaf)) {
                            Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-$role-input-file-missing" "Artifact '$artifactId' references a missing $role input: $inputPathValue"
                            $artifactValidationOk = $false
                            continue
                        }

                        $declaredInputSha256 = [string](Get-JsonValue $artifactJson $inputHashName)
                        if ([string]::IsNullOrWhiteSpace($declaredInputSha256)) {
                            Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-$role-input-hash-missing" "Artifact '$artifactId' does not declare $inputHashName."
                            $artifactValidationOk = $false
                        }
                        else {
                            $actualInputSha256 = Get-FileSha256 $resolvedInputPath
                            if (-not [string]::Equals($declaredInputSha256.Trim().ToLowerInvariant(), $actualInputSha256, [StringComparison]::OrdinalIgnoreCase)) {
                                Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-$role-input-hash-mismatch" "Artifact '$artifactId' reports $inputHashName='$declaredInputSha256' but '$inputPathValue' hashes to '$actualInputSha256'."
                                $artifactValidationOk = $false
                            }
                        }
                    }
                }

                $readyForReview = Test-Truthy (Get-JsonValue $artifactJson "readyForReview")
                $regressions = [int](Get-JsonValue $artifactJson "regressionCount")
                $hardConstraintRegressions = [int](Get-JsonValue $artifactJson "hardConstraintRegressionCount")
                $gateFailures = [int](Get-JsonValue $artifactJson "gateFailureCount")
                $missingMetrics = [int](Get-JsonValue $artifactJson "missingMetricValueCount")
                $candidateComparisonsValue = Get-JsonValue $artifactJson "candidateComparisonCount"
                $candidateComparisons = if ($null -eq $candidateComparisonsValue) { 1 } else { [int]$candidateComparisonsValue }
                $failedComparisons = [int](Get-JsonValue $artifactJson "failedComparisonCount")
                $missingBaselines = [int](Get-JsonValue $artifactJson "missingBaselineCount")
                $missingCandidates = [int](Get-JsonValue $artifactJson "missingCandidateCount")
                $metricRegressionDetails = @(Get-JsonArray $artifactJson "metricRegressionDetails")
                $hardConstraintRegressionDetails = @(Get-JsonArray $artifactJson "hardConstraintRegressionDetails")
                $gateFailureDetails = @(Get-JsonArray $artifactJson "gateFailureDetails")
                $missingMetricDetails = @(Get-JsonArray $artifactJson "missingMetricDetails")
                $metricRegressionSafetyClassCounts = @(Get-LiveTraceSafetyClassCounts `
                    -ArtifactJson $artifactJson `
                    -CountsName "metricRegressionSafetyClassCounts" `
                    -DetailsName "metricRegressionDetails" `
                    -MetricComparisonsVerdict "regression")
                $metricMissingSafetyClassCounts = @(Get-LiveTraceSafetyClassCounts `
                    -ArtifactJson $artifactJson `
                    -CountsName "metricMissingSafetyClassCounts" `
                    -DetailsName "missingMetricDetails" `
                    -MetricComparisonsVerdict "missing")
                $bundleRelativePaths = Test-Truthy (Get-JsonValue $artifactJson "bundleRelativePaths")
                $absolutePaths = if ($tool -eq "compare-dsp-live-diagnostics-traces" -or $tool -eq "compare-dsp-live-diagnostics-matrix") { @(Get-LiveTraceComparisonAbsolutePaths $artifactJson) } else { @() }
                $nr5WeakSignalSummary = Get-JsonValue $artifactJson "nr5WeakSignalComparisonSummary"
                if ($null -eq $nr5WeakSignalSummary) {
                    $nr5WeakSignalSummary = Get-JsonValue $artifactJson "nr5WeakSignalComparison"
                }
                $captureReadinessSummary = Get-LiveTraceCaptureReadinessSummary $artifactJson
                if ($null -eq $captureReadinessSummary) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-capture-readiness-summary-missing" "Artifact '$artifactId' must include captureReadinessComparison or captureReadinessComparisonSummary so strict validation can check setup hard gates separately from DSP regressions."
                    $artifactValidationOk = $false
                }
                $rxAudioLevelerSummary = Get-JsonValue $artifactJson "rxAudioLevelerComparisonSummary"
                if ($null -eq $rxAudioLevelerSummary) {
                    $rxAudioLevelerSummary = Get-JsonValue $artifactJson "rxAudioLevelerComparison"
                }
                if ($null -eq $rxAudioLevelerSummary) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-rx-audio-leveler-summary-missing" "Artifact '$artifactId' must include rxAudioLevelerComparison or rxAudioLevelerComparisonSummary so strict validation can check downstream leveler constraints."
                    $artifactValidationOk = $false
                }

                $metricDefinitions = @(Get-JsonArray $artifactJson "metricDefinitions")
                $reportedMetricDefinitionCountValue = Get-JsonValue $artifactJson "metricDefinitionCount"
                if ($null -ne $reportedMetricDefinitionCountValue -and [int](Get-NumericValueOrDefault $reportedMetricDefinitionCountValue) -ne $metricDefinitions.Count) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-metric-definition-count-mismatch" "Artifact '$artifactId' reports metricDefinitionCount=$([int](Get-NumericValueOrDefault $reportedMetricDefinitionCountValue)) but includes $($metricDefinitions.Count) metricDefinitions entries."
                    $artifactValidationOk = $false
                }

                $alignedMetricIds = New-Object System.Collections.Generic.List[string]
                $missingCatalogMetricIds = New-Object System.Collections.Generic.List[string]
                $directionMismatchMetricIds = New-Object System.Collections.Generic.List[string]
                $thresholdMismatchMetricIds = New-Object System.Collections.Generic.List[string]
                $comparatorMismatchMetricIds = New-Object System.Collections.Generic.List[string]
                $safetyClassMismatchMetricIds = New-Object System.Collections.Generic.List[string]
                $scopeMismatchMetricIds = New-Object System.Collections.Generic.List[string]
                $seenMetricDefinitionIds = @{}

                if ($metricDefinitions.Count -eq 0) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-metric-definitions-missing" "Artifact '$artifactId' must include metricDefinitions so live trace thresholds, directions, and safety classes can be checked against benchmark-metric-catalog.json."
                    $artifactValidationOk = $false
                }
                elseif ($null -eq $metricCatalog -or $metricCatalogEntriesById.Count -eq 0) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-metric-catalog-missing" "Artifact '$artifactId' includes metricDefinitions but benchmark-metric-catalog.json is missing or empty."
                    $artifactValidationOk = $false
                }
                else {
                    foreach ($definition in $metricDefinitions) {
                        $metricId = ConvertTo-MetricId ([string](Get-JsonValue $definition "id"))
                        if ([string]::IsNullOrWhiteSpace($metricId)) {
                            $metricId = ConvertTo-MetricId ([string](Get-JsonValue $definition "metricId"))
                        }
                        if ([string]::IsNullOrWhiteSpace($metricId) -or $seenMetricDefinitionIds.ContainsKey($metricId)) {
                            continue
                        }

                        $seenMetricDefinitionIds[$metricId] = $true
                        $metricAlignmentOk = $true
                        if (-not $metricCatalogEntriesById.ContainsKey($metricId)) {
                            $missingCatalogMetricIds.Add($metricId) | Out-Null
                            continue
                        }

                        $catalogMetric = $metricCatalogEntriesById[$metricId]
                        $definitionDirection = ([string](Get-JsonValue $definition "direction")).Trim().ToLowerInvariant()
                        $catalogDirection = ([string](Get-JsonValue $catalogMetric "direction")).Trim().ToLowerInvariant()
                        if ([string]::IsNullOrWhiteSpace($definitionDirection) -or -not [string]::Equals($definitionDirection, $catalogDirection, [StringComparison]::OrdinalIgnoreCase)) {
                            $directionMismatchMetricIds.Add($metricId) | Out-Null
                            $metricAlignmentOk = $false
                        }

                        $definitionThresholdValue = Get-JsonValue $definition "definitionThreshold"
                        if ($null -eq $definitionThresholdValue) {
                            $definitionThresholdValue = Get-JsonValue $definition "threshold"
                        }
                        $definitionThreshold = Get-NumericValue $definitionThresholdValue
                        $catalogThreshold = Get-NumericValue (Get-MetricCatalogFieldValue -Metric $catalogMetric -Names @("acceptanceThreshold", "threshold", "targetThreshold", "minimumThreshold", "maximumThreshold"))
                        if ($null -eq $definitionThreshold -or $null -eq $catalogThreshold -or [Math]::Abs([double]$definitionThreshold - [double]$catalogThreshold) -gt 0.000001) {
                            $thresholdMismatchMetricIds.Add($metricId) | Out-Null
                            $metricAlignmentOk = $false
                        }

                        $expectedComparator = if ($definitionDirection -eq "informational") { "informational" } else { "no-regression" }
                        $catalogComparator = ConvertTo-MetricCatalogComparator (Get-MetricCatalogFieldText -Metric $catalogMetric -Names @("acceptanceComparator", "thresholdComparator", "comparator", "thresholdDirection"))
                        if ([string]::IsNullOrWhiteSpace($catalogComparator) -or -not [string]::Equals($expectedComparator, $catalogComparator, [StringComparison]::OrdinalIgnoreCase)) {
                            $comparatorMismatchMetricIds.Add($metricId) | Out-Null
                            $metricAlignmentOk = $false
                        }

                        $definitionSafetyClass = ConvertTo-MetricCatalogToken ([string](Get-JsonValue $definition "safetyClass"))
                        $catalogSafetyClasses = @(Get-MetricCatalogFieldTokens -Metric $catalogMetric -Names @("safetyClass", "safetyClasses"))
                        if ([string]::IsNullOrWhiteSpace($definitionSafetyClass) -or @($catalogSafetyClasses | Where-Object { [string]::Equals([string]$_, $definitionSafetyClass, [StringComparison]::OrdinalIgnoreCase) }).Count -eq 0) {
                            $safetyClassMismatchMetricIds.Add($metricId) | Out-Null
                            $metricAlignmentOk = $false
                        }

                        $definitionScope = ConvertTo-MetricCatalogToken ([string](Get-JsonValue $definition "acceptanceScope"))
                        $catalogScopes = @(Get-MetricCatalogFieldTokens -Metric $catalogMetric -Names @("acceptanceScope", "acceptanceScopes", "scope", "scopes", "scenarioIds", "relatedScenarioIds", "relatedScenarios", "scenarios"))
                        if ([string]::IsNullOrWhiteSpace($definitionScope) -or @($catalogScopes | Where-Object { [string]::Equals([string]$_, $definitionScope, [StringComparison]::OrdinalIgnoreCase) }).Count -eq 0) {
                            $scopeMismatchMetricIds.Add($metricId) | Out-Null
                            $metricAlignmentOk = $false
                        }

                        if ($metricAlignmentOk) {
                            $alignedMetricIds.Add($metricId) | Out-Null
                        }
                    }
                }

                $missingCatalogMetricIds = @($missingCatalogMetricIds.ToArray() | Select-Object -Unique | Sort-Object)
                $directionMismatchMetricIds = @($directionMismatchMetricIds.ToArray() | Select-Object -Unique | Sort-Object)
                $thresholdMismatchMetricIds = @($thresholdMismatchMetricIds.ToArray() | Select-Object -Unique | Sort-Object)
                $comparatorMismatchMetricIds = @($comparatorMismatchMetricIds.ToArray() | Select-Object -Unique | Sort-Object)
                $safetyClassMismatchMetricIds = @($safetyClassMismatchMetricIds.ToArray() | Select-Object -Unique | Sort-Object)
                $scopeMismatchMetricIds = @($scopeMismatchMetricIds.ToArray() | Select-Object -Unique | Sort-Object)
                $alignedMetricIds = @($alignedMetricIds.ToArray() | Select-Object -Unique | Sort-Object)

                if ($missingCatalogMetricIds.Count -gt 0) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-metric-catalog-metric-missing" "Artifact '$artifactId' includes metricDefinitions missing from benchmark-metric-catalog.json: $($missingCatalogMetricIds -join ', ')."
                    $artifactValidationOk = $false
                }
                if ($directionMismatchMetricIds.Count -gt 0) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-metric-catalog-direction-mismatch" "Artifact '$artifactId' metricDefinitions disagree with benchmark-metric-catalog.json direction values: $($directionMismatchMetricIds -join ', ')."
                    $artifactValidationOk = $false
                }
                if ($thresholdMismatchMetricIds.Count -gt 0) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-metric-catalog-threshold-mismatch" "Artifact '$artifactId' metricDefinitions disagree with benchmark-metric-catalog.json acceptance thresholds: $($thresholdMismatchMetricIds -join ', ')."
                    $artifactValidationOk = $false
                }
                if ($comparatorMismatchMetricIds.Count -gt 0) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-metric-catalog-comparator-mismatch" "Artifact '$artifactId' metricDefinitions disagree with benchmark-metric-catalog.json acceptance comparators: $($comparatorMismatchMetricIds -join ', ')."
                    $artifactValidationOk = $false
                }
                if ($safetyClassMismatchMetricIds.Count -gt 0) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-metric-catalog-safety-class-mismatch" "Artifact '$artifactId' metricDefinitions disagree with benchmark-metric-catalog.json safety classes: $($safetyClassMismatchMetricIds -join ', ')."
                    $artifactValidationOk = $false
                }
                if ($scopeMismatchMetricIds.Count -gt 0) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-metric-catalog-scope-mismatch" "Artifact '$artifactId' metricDefinitions are not scoped to the same benchmark-metric-catalog.json acceptance surface: $($scopeMismatchMetricIds -join ', ')."
                    $artifactValidationOk = $false
                }

                $metricCatalogAlignmentReady = ($metricDefinitions.Count -gt 0 -and
                    $null -ne $metricCatalog -and
                    $metricCatalogEntriesById.Count -gt 0 -and
                    $missingCatalogMetricIds.Count -eq 0 -and
                    $directionMismatchMetricIds.Count -eq 0 -and
                    $thresholdMismatchMetricIds.Count -eq 0 -and
                    $comparatorMismatchMetricIds.Count -eq 0 -and
                    $safetyClassMismatchMetricIds.Count -eq 0 -and
                    $scopeMismatchMetricIds.Count -eq 0)
                $metricCatalogAlignmentStatus = if ($metricCatalogAlignmentReady) {
                    "ready"
                }
                elseif ($metricDefinitions.Count -eq 0) {
                    "metric-definitions-missing"
                }
                elseif ($null -eq $metricCatalog -or $metricCatalogEntriesById.Count -eq 0) {
                    "metric-catalog-missing"
                }
                else {
                    "metric-catalog-mismatch"
                }

                if ($tool -eq "compare-dsp-live-diagnostics-matrix") {
                    $matrixScenarioComparisons = @(Get-JsonArray $artifactJson "scenarioComparisons")
                    $matrixMissingScenarioPairs = @(Get-JsonArray $artifactJson "missingScenarioPairs")
                    $expectedMatrixCandidateComparisons = $matrixScenarioComparisons.Count
                    $expectedMatrixFailedComparisons = 0
                    $expectedMatrixRegressions = 0
                    $expectedMatrixImprovements = 0
                    $expectedMatrixHardConstraintRegressions = 0
                    $expectedMatrixGateFailures = 0
                    $expectedMatrixMissingMetrics = 0
                    $expectedMatrixMissingBaselines = @($matrixMissingScenarioPairs | Where-Object { [string](Get-JsonValue $_ "missing") -eq "baseline" }).Count
                    $expectedMatrixMissingCandidates = @($matrixMissingScenarioPairs | Where-Object { [string](Get-JsonValue $_ "missing") -eq "candidate" }).Count

                    foreach ($scenarioComparison in $matrixScenarioComparisons) {
                        if (-not [string]::IsNullOrWhiteSpace([string](Get-JsonValue $scenarioComparison "error"))) {
                            $expectedMatrixFailedComparisons++
                        }
                        $expectedMatrixRegressions += [int](Get-NumericValueOrDefault (Get-JsonValue $scenarioComparison "regressionCount"))
                        $expectedMatrixImprovements += [int](Get-NumericValueOrDefault (Get-JsonValue $scenarioComparison "improvementCount"))
                        $expectedMatrixHardConstraintRegressions += [int](Get-NumericValueOrDefault (Get-JsonValue $scenarioComparison "hardConstraintRegressionCount"))
                        $expectedMatrixGateFailures += [int](Get-NumericValueOrDefault (Get-JsonValue $scenarioComparison "gateFailureCount"))
                        $expectedMatrixMissingMetrics += [int](Get-NumericValueOrDefault (Get-JsonValue $scenarioComparison "missingMetricValueCount"))
                    }

                    $scenarioCaptureComparisons = @($matrixScenarioComparisons | ForEach-Object { Get-JsonValue $_ "captureReadinessComparison" } | Where-Object { $null -ne $_ })
                    $expectedCaptureReadinessSummary = New-LiveTraceCaptureReadinessSummary -Comparisons $scenarioCaptureComparisons
                    if ($null -ne $captureReadinessSummary) {
                        foreach ($captureSummaryCountSpec in @(
                                @{ Name = "scenarioComparisonCount"; Reported = [int](Get-NumericValueOrDefault (Get-JsonValue $captureReadinessSummary "scenarioComparisonCount")); Expected = [int](Get-NumericValueOrDefault (Get-JsonValue $expectedCaptureReadinessSummary "scenarioComparisonCount")) },
                                @{ Name = "candidateHardGatePassCount"; Reported = [int](Get-NumericValueOrDefault (Get-JsonValue $captureReadinessSummary "candidateHardGatePassCount")); Expected = [int](Get-NumericValueOrDefault (Get-JsonValue $expectedCaptureReadinessSummary "candidateHardGatePassCount")) },
                                @{ Name = "candidateHardGateFailCount"; Reported = [int](Get-NumericValueOrDefault (Get-JsonValue $captureReadinessSummary "candidateHardGateFailCount")); Expected = [int](Get-NumericValueOrDefault (Get-JsonValue $expectedCaptureReadinessSummary "candidateHardGateFailCount")) },
                                @{ Name = "candidateStrictPreflightPassCount"; Reported = [int](Get-NumericValueOrDefault (Get-JsonValue $captureReadinessSummary "candidateStrictPreflightPassCount")); Expected = [int](Get-NumericValueOrDefault (Get-JsonValue $expectedCaptureReadinessSummary "candidateStrictPreflightPassCount")) },
                                @{ Name = "candidateStrictPreflightFailCount"; Reported = [int](Get-NumericValueOrDefault (Get-JsonValue $captureReadinessSummary "candidateStrictPreflightFailCount")); Expected = [int](Get-NumericValueOrDefault (Get-JsonValue $expectedCaptureReadinessSummary "candidateStrictPreflightFailCount")) }
                            )) {
                            if ([int]$captureSummaryCountSpec["Reported"] -ne [int]$captureSummaryCountSpec["Expected"]) {
                                Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-capture-readiness-summary-mismatch" "Artifact '$artifactId' captureReadinessComparisonSummary.$([string]$captureSummaryCountSpec["Name"])=$([int]$captureSummaryCountSpec["Reported"]) but scenario rows produce $([int]$captureSummaryCountSpec["Expected"])."
                                $artifactValidationOk = $false
                            }
                        }

                        foreach ($captureSummaryArraySpec in @(
                                @{ Name = "candidateStatusCounts"; Field = "status" },
                                @{ Name = "candidateTopConstraintCounts"; Field = "constraint" },
                                @{ Name = "candidateTopHardConstraintCounts"; Field = "constraint" }
                            )) {
                            $arrayName = [string]$captureSummaryArraySpec["Name"]
                            $nameField = [string]$captureSummaryArraySpec["Field"]
                            if (-not (Test-LiveTraceCaptureCountsMatch `
                                    -Actual (Get-JsonArray $captureReadinessSummary $arrayName) `
                                    -Expected (Get-JsonArray $expectedCaptureReadinessSummary $arrayName) `
                                    -NameField $nameField)) {
                                Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-capture-readiness-summary-mismatch" "Artifact '$artifactId' captureReadinessComparisonSummary.$arrayName does not match scenario rows."
                                $artifactValidationOk = $false
                            }
                        }
                    }

                    if ($matrixScenarioComparisons.Count -eq 0) {
                        Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-scenario-comparisons-missing" "Artifact '$artifactId' matrix report does not include scenarioComparisons."
                        $artifactValidationOk = $false
                    }

                    foreach ($countSpec in @(
                            @{ Name = "candidateComparisonCount"; Reported = $candidateComparisons; Expected = $expectedMatrixCandidateComparisons; Code = "live-trace-comparison-matrix-candidate-count-mismatch" },
                            @{ Name = "failedComparisonCount"; Reported = $failedComparisons; Expected = $expectedMatrixFailedComparisons; Code = "live-trace-comparison-matrix-failed-count-mismatch" },
                            @{ Name = "missingBaselineCount"; Reported = $missingBaselines; Expected = $expectedMatrixMissingBaselines; Code = "live-trace-comparison-matrix-missing-baseline-count-mismatch" },
                            @{ Name = "missingCandidateCount"; Reported = $missingCandidates; Expected = $expectedMatrixMissingCandidates; Code = "live-trace-comparison-matrix-missing-candidate-count-mismatch" },
                            @{ Name = "regressionCount"; Reported = $regressions; Expected = $expectedMatrixRegressions; Code = "live-trace-comparison-matrix-regression-count-mismatch" },
                            @{ Name = "improvementCount"; Reported = [int](Get-NumericValueOrDefault (Get-JsonValue $artifactJson "improvementCount")); Expected = $expectedMatrixImprovements; Code = "live-trace-comparison-matrix-improvement-count-mismatch" },
                            @{ Name = "hardConstraintRegressionCount"; Reported = $hardConstraintRegressions; Expected = $expectedMatrixHardConstraintRegressions; Code = "live-trace-comparison-matrix-hard-constraint-count-mismatch" },
                            @{ Name = "gateFailureCount"; Reported = $gateFailures; Expected = $expectedMatrixGateFailures; Code = "live-trace-comparison-matrix-gate-count-mismatch" },
                            @{ Name = "missingMetricValueCount"; Reported = $missingMetrics; Expected = $expectedMatrixMissingMetrics; Code = "live-trace-comparison-matrix-missing-metric-count-mismatch" }
                        )) {
                        $reportedCount = [int]$countSpec["Reported"]
                        $expectedCount = [int]$countSpec["Expected"]
                        if ($reportedCount -ne $expectedCount) {
                            Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired ([string]$countSpec["Code"]) "Artifact '$artifactId' reports $([string]$countSpec["Name"])=$reportedCount but scenario rows/missing pairs produce $expectedCount."
                            $artifactValidationOk = $false
                        }
                    }

                    $expectedMatrixReadyForReview = ($expectedMatrixCandidateComparisons -gt 0 -and
                        $expectedMatrixFailedComparisons -eq 0 -and
                        $expectedMatrixMissingBaselines -eq 0 -and
                        $expectedMatrixMissingCandidates -eq 0 -and
                        $expectedMatrixRegressions -eq 0 -and
                        $expectedMatrixHardConstraintRegressions -eq 0 -and
                        $expectedMatrixGateFailures -eq 0 -and
                        $expectedMatrixMissingMetrics -eq 0)
                    if ($readyForReview -ne $expectedMatrixReadyForReview) {
                        Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-matrix-ready-mismatch" "Artifact '$artifactId' readyForReview=$readyForReview does not match scenario rows/missing pairs readiness $expectedMatrixReadyForReview."
                        $artifactValidationOk = $false
                    }

                    $comparisonIndexEvidenceByRole = @{}
                    foreach ($indexSpec in @(
                            @{ Role = "baseline"; PathName = "baselineIndexPath"; HashName = "baselineIndexSha256"; RootPathName = "baselineRootPath" },
                            @{ Role = "candidate"; PathName = "candidateIndexPath"; HashName = "candidateIndexSha256"; RootPathName = "candidateRootPath" }
                        )) {
                        $role = [string]$indexSpec["Role"]
                        $indexPathName = [string]$indexSpec["PathName"]
                        $indexHashName = [string]$indexSpec["HashName"]
                        $rootPathName = [string]$indexSpec["RootPathName"]
                        $indexPathValue = [string](Get-JsonValue $artifactJson $indexPathName)
                        if ([string]::IsNullOrWhiteSpace($indexPathValue)) {
                            Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-$role-index-path-missing" "Artifact '$artifactId' does not declare $indexPathName."
                            $artifactValidationOk = $false
                            continue
                        }

                        $resolvedComparisonIndexPath = Get-BundlePath $bundlePath $indexPathValue
                        if (-not (Test-Path -LiteralPath $resolvedComparisonIndexPath -PathType Leaf)) {
                            Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-$role-index-file-missing" "Artifact '$artifactId' references a missing $role trace index: $indexPathValue"
                            $artifactValidationOk = $false
                            continue
                        }

                        $declaredComparisonIndexSha256 = [string](Get-JsonValue $artifactJson $indexHashName)
                        if ([string]::IsNullOrWhiteSpace($declaredComparisonIndexSha256)) {
                            Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-$role-index-hash-missing" "Artifact '$artifactId' does not declare $indexHashName."
                            $artifactValidationOk = $false
                        }
                        else {
                            $actualComparisonIndexSha256 = Get-FileSha256 $resolvedComparisonIndexPath
                            if (-not [string]::Equals($declaredComparisonIndexSha256.Trim().ToLowerInvariant(), $actualComparisonIndexSha256, [StringComparison]::OrdinalIgnoreCase)) {
                                Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-$role-index-hash-mismatch" "Artifact '$artifactId' reports $indexHashName='$declaredComparisonIndexSha256' but '$indexPathValue' hashes to '$actualComparisonIndexSha256'."
                                $artifactValidationOk = $false
                            }
                        }

                        $comparisonIndexJson = $null
                        try {
                            $comparisonIndexJson = Read-JsonFile $resolvedComparisonIndexPath
                        }
                        catch {
                            Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-$role-index-json-invalid" $_.Exception.Message
                            $artifactValidationOk = $false
                        }

                        if ($null -ne $comparisonIndexJson) {
                            $rootPathValue = [string](Get-JsonValue $artifactJson $rootPathName)
                            $comparisonIndexRoot = if ([string]::IsNullOrWhiteSpace($rootPathValue)) {
                                Get-LiveTraceComparisonIndexRoot $resolvedComparisonIndexPath
                            }
                            else {
                                Get-BundlePath $bundlePath $rootPathValue
                            }
                            $comparisonIndexEvidenceByRole[$role] = [ordered]@{
                                path = $indexPathValue
                                resolvedPath = $resolvedComparisonIndexPath
                                root = $comparisonIndexRoot
                                entries = @(Get-JsonArray $comparisonIndexJson "files")
                            }
                        }
                    }

                    foreach ($scenarioComparison in $matrixScenarioComparisons) {
                        $scenarioId = [string](Get-JsonValue $scenarioComparison "scenarioId")
                        $baselineComparisonId = [string](Get-JsonValue $scenarioComparison "baselineComparisonId")
                        $candidateComparisonId = [string](Get-JsonValue $scenarioComparison "candidateComparisonId")
                        $scenarioLabel = if (-not [string]::IsNullOrWhiteSpace($scenarioId) -and -not [string]::IsNullOrWhiteSpace($candidateComparisonId)) { "$scenarioId/$candidateComparisonId" } else { "unknown-scenario" }
                        $normalizedScenarioId = ConvertTo-LiveHistoryScenarioId $scenarioId

                        foreach ($roleSpec in @(
                                @{ Role = "baseline"; ComparisonId = $baselineComparisonId; InputPathName = "baselineInputPath" },
                                @{ Role = "candidate"; ComparisonId = $candidateComparisonId; InputPathName = "candidateInputPath" }
                            )) {
                            $role = [string]$roleSpec["Role"]
                            if (-not $comparisonIndexEvidenceByRole.ContainsKey($role)) {
                                continue
                            }

                            $roleIndexEvidence = $comparisonIndexEvidenceByRole[$role]
                            $roleComparisonId = ConvertTo-ComparisonId ([string]$roleSpec["ComparisonId"])
                            $roleInputPathName = [string]$roleSpec["InputPathName"]
                            $recordInputPath = [string](Get-JsonValue $scenarioComparison $roleInputPathName)
                            $matchingIndexEntries = @($roleIndexEvidence["entries"] | Where-Object {
                                    $entryScenarioIds = @(Get-ArtifactIndexFileScenarioIds $_ | ForEach-Object { ConvertTo-LiveHistoryScenarioId ([string]$_) })
                                    $entryComparisonIds = @(Get-LiveTraceComparisonIndexEntryComparisonIds $_)
                                    $entryComparisonMatches = if ([string]::IsNullOrWhiteSpace($roleComparisonId)) {
                                        @($entryComparisonIds | Where-Object { [string]::IsNullOrWhiteSpace([string]$_) }).Count -gt 0
                                    }
                                    else {
                                        Test-StringArrayContains $entryComparisonIds $roleComparisonId
                                    }
                                    (Test-StringArrayContains $entryScenarioIds $normalizedScenarioId) -and
                                    $entryComparisonMatches
                                })

                            if ($matchingIndexEntries.Count -eq 0) {
                                Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-scenario-$role-index-entry-missing" "Artifact '$artifactId' scenario '$scenarioLabel' has no matching $role trace-index entry for scenario '$scenarioId' comparison '$([string]$roleSpec["ComparisonId"])'."
                                $artifactValidationOk = $false
                                continue
                            }
                            if ($matchingIndexEntries.Count -gt 1) {
                                Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-scenario-$role-index-entry-ambiguous" "Artifact '$artifactId' scenario '$scenarioLabel' matches $($matchingIndexEntries.Count) $role trace-index entries for scenario '$scenarioId' comparison '$([string]$roleSpec["ComparisonId"])'."
                                $artifactValidationOk = $false
                                continue
                            }

                            $matchingIndexEntry = $matchingIndexEntries[0]
                            $indexTracePath = Resolve-LiveTraceComparisonIndexEntryPath -IndexRoot ([string]$roleIndexEvidence["root"]) -Path (Get-ArtifactIndexFilePath $matchingIndexEntry)
                            $indexSummaryPath = Resolve-LiveTraceComparisonIndexEntryPath -IndexRoot ([string]$roleIndexEvidence["root"]) -Path (Get-ArtifactIndexFileSummaryPath $matchingIndexEntry)
                            $indexInputPath = if (-not [string]::IsNullOrWhiteSpace($indexSummaryPath) -and (Test-Path -LiteralPath $indexSummaryPath -PathType Leaf)) { $indexSummaryPath } else { $indexTracePath }
                            $indexInputSha256 = if (-not [string]::IsNullOrWhiteSpace($indexSummaryPath) -and (Test-Path -LiteralPath $indexSummaryPath -PathType Leaf)) { Get-ArtifactIndexFileSummarySha256 $matchingIndexEntry } else { Get-ArtifactIndexFileSha256 $matchingIndexEntry }

                            if ([string]::IsNullOrWhiteSpace($recordInputPath) -or [string]::IsNullOrWhiteSpace($indexInputPath) -or -not (Test-ComparableEvidencePathSame -BundlePath $bundlePath -ExpectedPath $indexInputPath -ActualPath $recordInputPath)) {
                                Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-scenario-$role-index-input-path-mismatch" "Artifact '$artifactId' scenario '$scenarioLabel' $roleInputPathName='$recordInputPath' does not match selected $role trace-index input path '$indexInputPath'."
                                $artifactValidationOk = $false
                            }

                            if ([string]::IsNullOrWhiteSpace($indexInputSha256)) {
                                Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-scenario-$role-index-input-hash-missing" "Artifact '$artifactId' scenario '$scenarioLabel' matched a $role trace-index entry without a hash for selected input '$indexInputPath'."
                                $artifactValidationOk = $false
                            }
                            elseif (-not [string]::IsNullOrWhiteSpace($indexInputPath) -and (Test-Path -LiteralPath $indexInputPath -PathType Leaf)) {
                                $actualIndexInputSha256 = Get-FileSha256 $indexInputPath
                                if (-not [string]::Equals($indexInputSha256.Trim().ToLowerInvariant(), $actualIndexInputSha256, [StringComparison]::OrdinalIgnoreCase)) {
                                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-scenario-$role-index-input-hash-mismatch" "Artifact '$artifactId' scenario '$scenarioLabel' $role trace-index entry declares selected input hash '$indexInputSha256' but '$indexInputPath' hashes to '$actualIndexInputSha256'."
                                    $artifactValidationOk = $false
                                }
                            }
                        }

                        $scenarioReportPath = [string](Get-JsonValue $scenarioComparison "reportPath")
                        if ([string]::IsNullOrWhiteSpace($scenarioReportPath)) {
                            Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-scenario-report-path-missing" "Artifact '$artifactId' scenario '$scenarioLabel' does not declare reportPath."
                            $artifactValidationOk = $false
                            continue
                        }

                        $resolvedScenarioReportPath = Get-BundlePath $bundlePath $scenarioReportPath
                        if (-not (Test-Path -LiteralPath $resolvedScenarioReportPath -PathType Leaf)) {
                            Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-scenario-report-file-missing" "Artifact '$artifactId' scenario '$scenarioLabel' references a missing scenario report: $scenarioReportPath"
                            $artifactValidationOk = $false
                            continue
                        }

                        $declaredScenarioReportSha256 = [string](Get-JsonValue $scenarioComparison "reportSha256")
                        if ([string]::IsNullOrWhiteSpace($declaredScenarioReportSha256)) {
                            Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-scenario-report-hash-missing" "Artifact '$artifactId' scenario '$scenarioLabel' does not declare reportSha256."
                            $artifactValidationOk = $false
                        }
                        else {
                            $actualScenarioReportSha256 = Get-FileSha256 $resolvedScenarioReportPath
                            if (-not [string]::Equals($declaredScenarioReportSha256.Trim().ToLowerInvariant(), $actualScenarioReportSha256, [StringComparison]::OrdinalIgnoreCase)) {
                                Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-scenario-report-hash-mismatch" "Artifact '$artifactId' scenario '$scenarioLabel' reports reportSha256='$declaredScenarioReportSha256' but '$scenarioReportPath' hashes to '$actualScenarioReportSha256'."
                                $artifactValidationOk = $false
                            }
                        }

                        $scenarioReportJson = $null
                        try {
                            $scenarioReportJson = Read-JsonFile $resolvedScenarioReportPath
                        }
                        catch {
                            Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-scenario-report-json-invalid" $_.Exception.Message
                            $artifactValidationOk = $false
                        }

                        if ($null -ne $scenarioReportJson) {
                            if ([string](Get-JsonValue $scenarioReportJson "tool") -ne "compare-dsp-live-diagnostics-traces") {
                                Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-scenario-report-tool-invalid" "Artifact '$artifactId' scenario '$scenarioLabel' report '$scenarioReportPath' was not generated by compare-dsp-live-diagnostics-traces.ps1."
                                $artifactValidationOk = $false
                            }

                            foreach ($inputSpec in @(
                                    @{ Role = "baseline"; PathName = "baselinePath"; HashName = "baselineInputSha256" },
                                    @{ Role = "candidate"; PathName = "candidatePath"; HashName = "candidateInputSha256" }
                                )) {
                                $inputRole = [string]$inputSpec["Role"]
                                $inputPathName = [string]$inputSpec["PathName"]
                                $inputHashName = [string]$inputSpec["HashName"]
                                $scenarioInputPath = [string](Get-JsonValue $scenarioReportJson $inputPathName)
                                if ([string]::IsNullOrWhiteSpace($scenarioInputPath)) {
                                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-scenario-report-$inputRole-input-path-missing" "Artifact '$artifactId' scenario '$scenarioLabel' report '$scenarioReportPath' does not declare $inputPathName."
                                    $artifactValidationOk = $false
                                    continue
                                }

                                $resolvedScenarioInputPath = Get-BundlePath $bundlePath $scenarioInputPath
                                if (-not (Test-Path -LiteralPath $resolvedScenarioInputPath -PathType Leaf)) {
                                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-scenario-report-$inputRole-input-file-missing" "Artifact '$artifactId' scenario '$scenarioLabel' report '$scenarioReportPath' references a missing $inputRole input: $scenarioInputPath"
                                    $artifactValidationOk = $false
                                    continue
                                }

                                $declaredScenarioInputSha256 = [string](Get-JsonValue $scenarioReportJson $inputHashName)
                                if ([string]::IsNullOrWhiteSpace($declaredScenarioInputSha256)) {
                                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-scenario-report-$inputRole-input-hash-missing" "Artifact '$artifactId' scenario '$scenarioLabel' report '$scenarioReportPath' does not declare $inputHashName."
                                    $artifactValidationOk = $false
                                }
                                else {
                                    $actualScenarioInputSha256 = Get-FileSha256 $resolvedScenarioInputPath
                                    if (-not [string]::Equals($declaredScenarioInputSha256.Trim().ToLowerInvariant(), $actualScenarioInputSha256, [StringComparison]::OrdinalIgnoreCase)) {
                                        Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-scenario-report-$inputRole-input-hash-mismatch" "Artifact '$artifactId' scenario '$scenarioLabel' report '$scenarioReportPath' reports $inputHashName='$declaredScenarioInputSha256' but '$scenarioInputPath' hashes to '$actualScenarioInputSha256'."
                                        $artifactValidationOk = $false
                                    }
                                }
                            }

                            if ((Test-Truthy (Get-JsonValue $scenarioComparison "readyForReview")) -ne (Test-Truthy (Get-JsonValue $scenarioReportJson "readyForReview"))) {
                                Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-scenario-report-ready-mismatch" "Artifact '$artifactId' scenario '$scenarioLabel' readyForReview does not match '$scenarioReportPath'."
                                $artifactValidationOk = $false
                            }

                            foreach ($countField in @("regressionCount", "improvementCount", "hardConstraintRegressionCount", "gateFailureCount", "missingMetricValueCount")) {
                                $recordCount = [int](Get-NumericValueOrDefault (Get-JsonValue $scenarioComparison $countField))
                                $reportCount = [int](Get-NumericValueOrDefault (Get-JsonValue $scenarioReportJson $countField))
                                if ($recordCount -ne $reportCount) {
                                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-scenario-report-count-mismatch" "Artifact '$artifactId' scenario '$scenarioLabel' reports $countField=$recordCount but '$scenarioReportPath' reports $reportCount."
                                    $artifactValidationOk = $false
                                }
                            }

                            $recordCaptureReadinessComparison = Get-JsonValue $scenarioComparison "captureReadinessComparison"
                            $reportCaptureReadinessComparison = Get-JsonValue $scenarioReportJson "captureReadinessComparison"
                            if ($null -eq $recordCaptureReadinessComparison -or $null -eq $reportCaptureReadinessComparison) {
                                Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-scenario-report-capture-readiness-missing" "Artifact '$artifactId' scenario '$scenarioLabel' must carry captureReadinessComparison in both the matrix row and '$scenarioReportPath'."
                                $artifactValidationOk = $false
                            }
                            else {
                                foreach ($captureFieldSpec in @(
                                        @{ Name = "candidateStatus"; Kind = "text" },
                                        @{ Name = "candidateHardGatePass"; Kind = "bool" },
                                        @{ Name = "candidateStrictPreflightPass"; Kind = "bool" },
                                        @{ Name = "candidateTopConstraintName"; Kind = "text" },
                                        @{ Name = "candidateTopConstraintCount"; Kind = "number" },
                                        @{ Name = "candidateTopHardConstraintName"; Kind = "text" },
                                        @{ Name = "candidateTopHardConstraintCount"; Kind = "number" }
                                    )) {
                                    $captureFieldName = [string]$captureFieldSpec["Name"]
                                    $captureKind = [string]$captureFieldSpec["Kind"]
                                    if ($captureKind -eq "bool") {
                                        if ((Test-Truthy (Get-JsonValue $recordCaptureReadinessComparison $captureFieldName)) -ne (Test-Truthy (Get-JsonValue $reportCaptureReadinessComparison $captureFieldName))) {
                                            Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-scenario-report-capture-readiness-mismatch" "Artifact '$artifactId' scenario '$scenarioLabel' captureReadinessComparison.$captureFieldName does not match '$scenarioReportPath'."
                                            $artifactValidationOk = $false
                                        }
                                    }
                                    elseif ($captureKind -eq "number") {
                                        $recordValue = [int](Get-NumericValueOrDefault (Get-JsonValue $recordCaptureReadinessComparison $captureFieldName))
                                        $reportValue = [int](Get-NumericValueOrDefault (Get-JsonValue $reportCaptureReadinessComparison $captureFieldName))
                                        if ($recordValue -ne $reportValue) {
                                            Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-scenario-report-capture-readiness-mismatch" "Artifact '$artifactId' scenario '$scenarioLabel' captureReadinessComparison.$captureFieldName=$recordValue but '$scenarioReportPath' reports $reportValue."
                                            $artifactValidationOk = $false
                                        }
                                    }
                                    else {
                                        $recordValue = [string](Get-JsonValue $recordCaptureReadinessComparison $captureFieldName)
                                        $reportValue = [string](Get-JsonValue $reportCaptureReadinessComparison $captureFieldName)
                                        if (-not [string]::Equals($recordValue, $reportValue, [StringComparison]::OrdinalIgnoreCase)) {
                                            Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-scenario-report-capture-readiness-mismatch" "Artifact '$artifactId' scenario '$scenarioLabel' captureReadinessComparison.$captureFieldName='$recordValue' but '$scenarioReportPath' reports '$reportValue'."
                                            $artifactValidationOk = $false
                                        }
                                    }
                                }
                            }

                            $recordBaselinePath = [string](Get-JsonValue $scenarioComparison "baselineInputPath")
                            $reportBaselinePath = [string](Get-JsonValue $scenarioReportJson "baselinePath")
                            if ([string]::IsNullOrWhiteSpace($recordBaselinePath) -or [string]::IsNullOrWhiteSpace($reportBaselinePath) -or -not (Test-ComparableEvidencePathSame -BundlePath $bundlePath -ExpectedPath $recordBaselinePath -ActualPath $reportBaselinePath)) {
                                Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-scenario-baseline-path-mismatch" "Artifact '$artifactId' scenario '$scenarioLabel' baselineInputPath='$recordBaselinePath' does not match scenario report baselinePath='$reportBaselinePath'."
                                $artifactValidationOk = $false
                            }

                            $recordCandidatePath = [string](Get-JsonValue $scenarioComparison "candidateInputPath")
                            $reportCandidatePath = [string](Get-JsonValue $scenarioReportJson "candidatePath")
                            if ([string]::IsNullOrWhiteSpace($recordCandidatePath) -or [string]::IsNullOrWhiteSpace($reportCandidatePath) -or -not (Test-ComparableEvidencePathSame -BundlePath $bundlePath -ExpectedPath $recordCandidatePath -ActualPath $reportCandidatePath)) {
                                Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-scenario-candidate-path-mismatch" "Artifact '$artifactId' scenario '$scenarioLabel' candidateInputPath='$recordCandidatePath' does not match scenario report candidatePath='$reportCandidatePath'."
                                $artifactValidationOk = $false
                            }
                        }
                    }
                }

                $liveTraceComparisonEvidence["readyForReview"] = $readyForReview
                $liveTraceComparisonEvidence["candidateComparisonCount"] = $candidateComparisons
                $liveTraceComparisonEvidence["failedComparisonCount"] = $failedComparisons
                $liveTraceComparisonEvidence["missingBaselineCount"] = $missingBaselines
                $liveTraceComparisonEvidence["missingCandidateCount"] = $missingCandidates
                $liveTraceComparisonEvidence["regressionCount"] = $regressions
                $liveTraceComparisonEvidence["hardConstraintRegressionCount"] = $hardConstraintRegressions
                $liveTraceComparisonEvidence["gateFailureCount"] = $gateFailures
                $liveTraceComparisonEvidence["missingMetricValueCount"] = $missingMetrics
                $liveTraceComparisonEvidence["metricRegressionDetailCount"] = $metricRegressionDetails.Count
                $liveTraceComparisonEvidence["hardConstraintRegressionDetailCount"] = $hardConstraintRegressionDetails.Count
                $liveTraceComparisonEvidence["gateFailureDetailCount"] = $gateFailureDetails.Count
                $liveTraceComparisonEvidence["missingMetricDetailCount"] = $missingMetricDetails.Count
                $liveTraceComparisonEvidence["metricRegressionSafetyClassCounts"] = @($metricRegressionSafetyClassCounts)
                $liveTraceComparisonEvidence["metricMissingSafetyClassCounts"] = @($metricMissingSafetyClassCounts)
                $liveTraceComparisonEvidence["pumpingRegressionCount"] = Get-SafetyClassCount $metricRegressionSafetyClassCounts "pumping"
                $liveTraceComparisonEvidence["weakSignalRegressionCount"] = Get-SafetyClassCount $metricRegressionSafetyClassCounts "weak-signal"
                $liveTraceComparisonEvidence["clippingRegressionCount"] = Get-SafetyClassCount $metricRegressionSafetyClassCounts "clipping"
                $liveTraceComparisonEvidence["readinessRegressionCount"] = Get-SafetyClassCount $metricRegressionSafetyClassCounts "readiness"
                $liveTraceComparisonEvidence["hardGateRegressionCount"] = Get-SafetyClassCount $metricRegressionSafetyClassCounts "hard-gate"
                $liveTraceComparisonEvidence["freshnessRegressionCount"] = Get-SafetyClassCount $metricRegressionSafetyClassCounts "freshness"
                $liveTraceComparisonEvidence["frontEndRegressionCount"] = Get-SafetyClassCount $metricRegressionSafetyClassCounts "front-end"
                $liveTraceComparisonEvidence["audioPathRegressionCount"] = Get-SafetyClassCount $metricRegressionSafetyClassCounts "audio-path"
                $liveTraceComparisonEvidence["toolingRegressionCount"] = Get-SafetyClassCount $metricRegressionSafetyClassCounts "tooling"
                $liveTraceComparisonEvidence["bundleRelativePaths"] = $bundleRelativePaths
                $liveTraceComparisonEvidence["absolutePathCount"] = $absolutePaths.Count
                $liveTraceComparisonEvidence["metricDefinitionCount"] = $metricDefinitions.Count
                $liveTraceComparisonEvidence["metricCatalogAlignedMetricCount"] = $alignedMetricIds.Count
                $liveTraceComparisonEvidence["metricCatalogMissingMetricCount"] = $missingCatalogMetricIds.Count
                $liveTraceComparisonEvidence["metricCatalogMissingMetricIds"] = @($missingCatalogMetricIds)
                $liveTraceComparisonEvidence["metricCatalogDirectionMismatchCount"] = $directionMismatchMetricIds.Count
                $liveTraceComparisonEvidence["metricCatalogDirectionMismatchMetricIds"] = @($directionMismatchMetricIds)
                $liveTraceComparisonEvidence["metricCatalogThresholdMismatchCount"] = $thresholdMismatchMetricIds.Count
                $liveTraceComparisonEvidence["metricCatalogThresholdMismatchMetricIds"] = @($thresholdMismatchMetricIds)
                $liveTraceComparisonEvidence["metricCatalogComparatorMismatchCount"] = $comparatorMismatchMetricIds.Count
                $liveTraceComparisonEvidence["metricCatalogComparatorMismatchMetricIds"] = @($comparatorMismatchMetricIds)
                $liveTraceComparisonEvidence["metricCatalogSafetyClassMismatchCount"] = $safetyClassMismatchMetricIds.Count
                $liveTraceComparisonEvidence["metricCatalogSafetyClassMismatchMetricIds"] = @($safetyClassMismatchMetricIds)
                $liveTraceComparisonEvidence["metricCatalogScopeMismatchCount"] = $scopeMismatchMetricIds.Count
                $liveTraceComparisonEvidence["metricCatalogScopeMismatchMetricIds"] = @($scopeMismatchMetricIds)
                $liveTraceComparisonEvidence["metricCatalogAlignmentReady"] = $metricCatalogAlignmentReady
                $liveTraceComparisonEvidence["metricCatalogAlignmentStatus"] = $metricCatalogAlignmentStatus
                $liveTraceComparisonEvidence["nr5WeakSignalComparisonSummary"] = $nr5WeakSignalSummary
                $liveTraceComparisonEvidence["captureReadinessComparisonSummary"] = $captureReadinessSummary
                $liveTraceComparisonEvidence["rxAudioLevelerComparisonSummary"] = $rxAudioLevelerSummary
                if ($null -ne $captureReadinessSummary) {
                    $liveTraceComparisonEvidence["captureReadinessScenarioComparisonCount"] = [int](Get-NumericValueOrDefault (Get-JsonValue $captureReadinessSummary "scenarioComparisonCount"))
                    $liveTraceComparisonEvidence["captureReadinessCandidateHardGatePassCount"] = [int](Get-NumericValueOrDefault (Get-JsonValue $captureReadinessSummary "candidateHardGatePassCount"))
                    $liveTraceComparisonEvidence["captureReadinessCandidateHardGateFailCount"] = [int](Get-NumericValueOrDefault (Get-JsonValue $captureReadinessSummary "candidateHardGateFailCount"))
                    $liveTraceComparisonEvidence["captureReadinessCandidateStrictPreflightPassCount"] = [int](Get-NumericValueOrDefault (Get-JsonValue $captureReadinessSummary "candidateStrictPreflightPassCount"))
                    $liveTraceComparisonEvidence["captureReadinessCandidateStrictPreflightFailCount"] = [int](Get-NumericValueOrDefault (Get-JsonValue $captureReadinessSummary "candidateStrictPreflightFailCount"))
                    $liveTraceComparisonEvidence["captureReadinessCandidateStatusCounts"] = @(Get-JsonArray $captureReadinessSummary "candidateStatusCounts")
                    $liveTraceComparisonEvidence["captureReadinessCandidateTopConstraintCounts"] = @(Get-JsonArray $captureReadinessSummary "candidateTopConstraintCounts")
                    $liveTraceComparisonEvidence["captureReadinessCandidateTopHardConstraintCounts"] = @(Get-JsonArray $captureReadinessSummary "candidateTopHardConstraintCounts")
                }
                if ($null -ne $nr5WeakSignalSummary) {
                    $liveTraceComparisonEvidence["nr5WeakInputSampleDelta"] = [int](Get-NumericValue (Get-JsonValue $nr5WeakSignalSummary "weakInputSampleDelta"))
                    $liveTraceComparisonEvidence["nr5WeakRecoveredSampleDelta"] = [int](Get-NumericValue (Get-JsonValue $nr5WeakSignalSummary "weakRecoveredSampleDelta"))
                    $liveTraceComparisonEvidence["nr5WeakDropoutSampleDelta"] = [int](Get-NumericValue (Get-JsonValue $nr5WeakSignalSummary "weakDropoutSampleDelta"))
                    $liveTraceComparisonEvidence["nr5HotMakeupSampleDelta"] = [int](Get-NumericValue (Get-JsonValue $nr5WeakSignalSummary "hotMakeupSampleDelta"))
                    $liveTraceComparisonEvidence["nr5WeakRecoveryPctDelta"] = [Math]::Round([double](Get-NumericValue (Get-JsonValue $nr5WeakSignalSummary "weakRecoveryPctDelta")), 3)
                    $liveTraceComparisonEvidence["nr5OutputMovementDbDelta"] = [Math]::Round([double](Get-NumericValueOrDefault (Get-JsonValue $nr5WeakSignalSummary "outputMovementDbDelta")), 3)
                    $liveTraceComparisonEvidence["nr5MakeupMovementDbDelta"] = [Math]::Round([double](Get-NumericValueOrDefault (Get-JsonValue $nr5WeakSignalSummary "makeupMovementDbDelta")), 3)
                    $liveTraceComparisonEvidence["nr5MakeupMaxDbDelta"] = [Math]::Round([double](Get-NumericValueOrDefault (Get-JsonValue $nr5WeakSignalSummary "makeupMaxDbDelta")), 3)
                    $liveTraceComparisonEvidence["nr5RecoveryDriveMovementDelta"] = [Math]::Round([double](Get-NumericValueOrDefault (Get-JsonValue $nr5WeakSignalSummary "recoveryDriveMovementDelta")), 3)
                    $liveTraceComparisonEvidence["nr5TextureFillAverageDelta"] = [Math]::Round([double](Get-NumericValueOrDefault (Get-JsonValue $nr5WeakSignalSummary "textureFillAverageDelta")), 3)
                    $liveTraceComparisonEvidence["nr5OutputMovementRegressionCount"] = Get-RegressionCountFromSummary $nr5WeakSignalSummary "outputMovementRegressionCount" "outputMovementRegression"
                    $liveTraceComparisonEvidence["nr5MakeupMovementRegressionCount"] = Get-RegressionCountFromSummary $nr5WeakSignalSummary "makeupMovementRegressionCount" "makeupMovementRegression"
                    $liveTraceComparisonEvidence["nr5MakeupMaxRegressionCount"] = Get-RegressionCountFromSummary $nr5WeakSignalSummary "makeupMaxRegressionCount" "makeupMaxRegression"
                    $liveTraceComparisonEvidence["nr5RecoveryDriveMovementRegressionCount"] = Get-RegressionCountFromSummary $nr5WeakSignalSummary "recoveryDriveMovementRegressionCount" "recoveryDriveMovementRegression"
                }
                if ($null -ne $rxAudioLevelerSummary) {
                    $liveTraceComparisonEvidence["rxAudioLevelerConstrainedSampleDelta"] = [int](Get-NumericValueOrDefault (Get-JsonValue $rxAudioLevelerSummary "constrainedSampleDelta"))
                    $liveTraceComparisonEvidence["rxAudioLevelerConstrainedPctDelta"] = [Math]::Round([double](Get-NumericValueOrDefault (Get-JsonValue $rxAudioLevelerSummary "constrainedPctDelta")), 3)
                    $liveTraceComparisonEvidence["rxAudioLevelerBoostSlewLimitedSampleDelta"] = [int](Get-NumericValueOrDefault (Get-JsonValue $rxAudioLevelerSummary "boostSlewLimitedSampleDelta"))
                    $liveTraceComparisonEvidence["rxAudioLevelerPeakLimitedSampleDelta"] = [int](Get-NumericValueOrDefault (Get-JsonValue $rxAudioLevelerSummary "peakLimitedSampleDelta"))
                    $liveTraceComparisonEvidence["rxAudioLevelerOutputLimitedSampleDelta"] = [int](Get-NumericValueOrDefault (Get-JsonValue $rxAudioLevelerSummary "outputLimitedSampleDelta"))
                    $liveTraceComparisonEvidence["rxAudioLevelerOutputRmsMovementDbDelta"] = [Math]::Round([double](Get-NumericValueOrDefault (Get-JsonValue $rxAudioLevelerSummary "outputRmsMovementDbDelta")), 3)
                    $liveTraceComparisonEvidence["rxAudioLevelerAppliedGainMovementDbDelta"] = [Math]::Round([double](Get-NumericValueOrDefault (Get-JsonValue $rxAudioLevelerSummary "appliedGainMovementDbDelta")), 3)
                    $liveTraceComparisonEvidence["rxAudioLevelerConstrainedRegressionCount"] = Get-RegressionCountFromSummary $rxAudioLevelerSummary "constrainedRegressionCount" "constrainedRegression"
                    $liveTraceComparisonEvidence["rxAudioLevelerConstrainedPctRegressionCount"] = Get-RegressionCountFromSummary $rxAudioLevelerSummary "constrainedPctRegressionCount" "constrainedPctRegression"
                    $liveTraceComparisonEvidence["rxAudioLevelerBoostSlewRegressionCount"] = Get-RegressionCountFromSummary $rxAudioLevelerSummary "boostSlewRegressionCount" "boostSlewRegression"
                    $liveTraceComparisonEvidence["rxAudioLevelerPeakLimitedRegressionCount"] = Get-RegressionCountFromSummary $rxAudioLevelerSummary "peakLimitedRegressionCount" "peakLimitedRegression"
                    $liveTraceComparisonEvidence["rxAudioLevelerOutputLimitedRegressionCount"] = Get-RegressionCountFromSummary $rxAudioLevelerSummary "outputLimitedRegressionCount" "outputLimitedRegression"
                }

                if ($candidateComparisons -le 0) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-candidate-missing" "Artifact '$artifactId' does not compare any candidate live trace scenario."
                    $artifactValidationOk = $false
                }
                if (($tool -eq "compare-dsp-live-diagnostics-traces" -or $tool -eq "compare-dsp-live-diagnostics-matrix") -and -not $bundleRelativePaths) {
                    $comparisonScript = if ($tool -eq "compare-dsp-live-diagnostics-matrix") { "compare-dsp-live-diagnostics-matrix.ps1" } else { "compare-dsp-live-diagnostics-traces.ps1" }
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-paths-not-bundle-relative" "Artifact '$artifactId' report was not generated with bundleRelativePaths=true; rerun $comparisonScript with -BundleDir."
                    $artifactValidationOk = $false
                }
                if ($absolutePaths.Count -gt 0) {
                    $pathExamples = Get-PathExampleText $absolutePaths
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-absolute-paths" "Artifact '$artifactId' report contains $($absolutePaths.Count) absolute path(s); rerun with -BundleDir so capture bundles are portable. Examples: $pathExamples"
                    $artifactValidationOk = $false
                }
                if ($failedComparisons -gt 0) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-failed" "Artifact '$artifactId' reports $failedComparisons failed per-scenario comparison(s)."
                    $artifactValidationOk = $false
                }
                if ($missingBaselines -gt 0) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-baseline-missing" "Artifact '$artifactId' is missing $missingBaselines baseline scenario trace(s)."
                    $artifactValidationOk = $false
                }
                if ($missingCandidates -gt 0) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-candidate-scenario-missing" "Artifact '$artifactId' is missing $missingCandidates candidate scenario trace(s)."
                    $artifactValidationOk = $false
                }
                if (-not $readyForReview) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-not-ready" "Artifact '$artifactId' reports readyForReview=false."
                    $artifactValidationOk = $false
                }
                if ($regressions -gt 0) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-regression" "Artifact '$artifactId' reports $regressions live diagnostics metric regression(s)."
                    $artifactValidationOk = $false
                }
                if ($hardConstraintRegressions -gt 0) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-hard-constraint-regression" "Artifact '$artifactId' reports $hardConstraintRegressions hard live diagnostics constraint regression(s)."
                    $artifactValidationOk = $false
                }
                if ($gateFailures -gt 0) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-gate-failed" "Artifact '$artifactId' reports $gateFailures live diagnostics gate failure(s)."
                    $artifactValidationOk = $false
                }
                if ($missingMetrics -gt 0) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-trace-comparison-value-missing" "Artifact '$artifactId' is missing $missingMetrics baseline/candidate metric value(s)."
                    $artifactValidationOk = $false
                }

                if ($artifactValidationOk) {
                    $liveTraceComparisonEvidence["status"] = "ready"
                }
                else {
                    $liveTraceComparisonEvidence["readyForReview"] = $false
                    $liveTraceComparisonEvidence["status"] = "not-ready"
                }

                if ($artifactId -eq $liveTraceThetisComparisonArtifactId) {
                    $liveTraceComparisonEvidence = $previousLiveTraceComparisonEvidence
                }
            }

            if ($artifactKind -ieq "diagnostics-history-json" -or $artifactId -eq $liveDiagnosticsHistoryArtifactId) {
                $liveDiagnosticsHistoryEvidence["present"] = $true

                $tool = [string](Get-JsonValue $artifactJson "tool")
                if ($tool -ne "summarize-dsp-live-diagnostics-history") {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-history-tool-invalid" "Artifact '$artifactId' must be generated by summarize-dsp-live-diagnostics-history.ps1."
                    $artifactValidationOk = $false
                }

                $schemaVersion = [int](Get-NumericValueOrDefault (Get-JsonValue $artifactJson "schemaVersion") 1)
                if ($tool -eq "summarize-dsp-live-diagnostics-history" -and $schemaVersion -ne 15) {
                    Add-ArtifactIssue $errors $warnings -Required:$effectiveRequired "live-history-schema-version-mismatch" "Artifact '$artifactId' schemaVersion=$schemaVersion but summarize-dsp-live-diagnostics-history.ps1 currently emits schemaVersion=15."
                    $artifactValidationOk = $false
                }
                $traceCount = [int](Get-JsonValue $artifactJson "traceCount")
                $nr5TraceCount = [int](Get-JsonValue $artifactJson "nr5TraceCount")
                $readyTraceCount = [int](Get-JsonValue $artifactJson "readyTraceCount")
                $readyNr5TraceCount = [int](Get-NumericValueOrDefault (Get-JsonValue $artifactJson "readyNr5TraceCount"))
                $candidateReadyNr5TraceCount = [int](Get-NumericValueOrDefault (Get-JsonValue $artifactJson "candidateReadyNr5TraceCount"))
                $latestTrace = Get-JsonValue $artifactJson "latestTrace"
                $previousNr5Trace = Get-JsonValue $artifactJson "previousNr5Trace"
                $bestBalancedTrace = Get-JsonValue $artifactJson "bestBalancedTrace"
                $bestWeakSignalTrace = Get-JsonValue $artifactJson "bestWeakSignalTrace"
                $lowestPumpingTrace = Get-JsonValue $artifactJson "lowestPumpingTrace"
                $mixedWeakStrongBestTrace = Get-JsonValue $artifactJson "mixedWeakStrongBestTrace"
                $promotionDecision = Get-JsonValue $artifactJson "latestNr5Decision"
                $legacyPromotionDecision = Get-JsonValue $artifactJson "promotionDecision"
                if ($null -eq $promotionDecision) {
                    $promotionDecision = $legacyPromotionDecision
                }
                $readinessTrend = Get-JsonValue $artifactJson "latestVsPreviousNr5ReadinessGapTrend"
                $legacyReadinessTrend = Get-JsonValue $artifactJson "latestVsPreviousReadinessTrend"
                if ($null -eq $readinessTrend) {
                    $readinessTrend = $legacyReadinessTrend
                }
                $referenceReadinessTrend = Get-JsonValue $artifactJson "latestVsReferenceNr5ReadinessGapTrend"
                $tuningActionPlan = Get-JsonValue $artifactJson "latestTuningActionPlan"
                $liveExperimentPlan = Get-JsonValue $artifactJson "latestLiveExperimentPlan"
                $liveExperimentCoverage = Get-JsonValue $artifactJson "latestLiveExperimentCoverage"
                $latestVsPreviousNr5Delta = Get-JsonValue $artifactJson "latestVsPreviousNr5Delta"
                $thresholds = Get-JsonValue $artifactJson "thresholds"
                $reviewStatusCounts = @(Get-JsonArray $artifactJson "reviewStatusCounts")
                $traceRecords = @(Get-JsonArray $artifactJson "traces")
                $aggregateSafetyClassCounts = @(Get-JsonArray $artifactJson "aggregateSafetyClassCounts")
                $aggregateReadinessGaps = @(Get-JsonArray $artifactJson "aggregateReadinessGaps")
                if ($aggregateReadinessGaps.Count -eq 0) {
                    $aggregateReadinessGaps = @(Get-JsonArray $artifactJson "aggregateSafetyClassReadiness")
                }
                $bundleRelativePaths = Test-Truthy (Get-JsonValue $artifactJson "bundleRelativePaths")
                $absolutePaths = if ($tool -eq "summarize-dsp-live-diagnostics-history") { @(Get-LiveDiagnosticsHistoryAbsolutePaths $artifactJson) } else { @() }
                $recommendations = @(Get-JsonArray $artifactJson "recommendations")
                $candidatePromotionReady = Test-Truthy (Get-JsonValue $promotionDecision "candidatePromotionReady")
                $defaultBehaviorChangeReady = Test-Truthy (Get-JsonValue $promotionDecision "defaultBehaviorChangeReady")
                $promotionStatus = [string](Get-JsonValue $promotionDecision "status")
                $promotionBlockers = @(Get-JsonArray $promotionDecision "blockers")
                $promotionBlockerClasses = @(Get-JsonArray $promotionDecision "blockerClasses" | ForEach-Object { [string]$_ })
                $promotionBlockerClassCounts = @(Get-JsonArray $promotionDecision "blockerClassCounts")
                $promotionBlockerCountValue = Get-NumericValue (Get-JsonValue $promotionDecision "blockerCount")
                $promotionBlockerCount = if ($null -eq $promotionBlockerCountValue) { $promotionBlockers.Count } else { [int][Math]::Round($promotionBlockerCountValue) }
                $promotionRecommendedTraceId = [string](Get-JsonValue $promotionDecision "recommendedTraceId")
                $promotionRecommendedTraceRole = [string](Get-JsonValue $promotionDecision "recommendedTraceRole")
                $promotionReferenceTraceId = [string](Get-JsonValue $promotionDecision "referenceTraceId")
                $promotionReferenceTraceRole = [string](Get-JsonValue $promotionDecision "referenceTraceRole")
                $promotable = Test-Truthy (Get-JsonValue $promotionDecision "promotable")
                $validPromotionStatuses = @(
                    "ready-for-candidate-comparison",
                    "blocked-hard-gate",
                    "blocked-clipping",
                    "blocked-diagnostic-freshness",
                    "blocked-runtime-evidence",
                    "blocked-weak-and-pumping",
                    "blocked-pumping",
                    "blocked-weak-signal",
                    "blocked-safety-signals",
                    "no-nr5-history"
                )
                $latestPromotionBlockerClasses = @(Get-JsonArray $latestTrace "promotionBlockerClasses" | ForEach-Object { [string]$_ })
                $latestCandidateReady = Test-Truthy (Get-JsonValue $latestTrace "candidateComparisonReady")
                $actualTraceCount = $traceRecords.Count
                $actualNr5TraceCount = @($traceRecords | Where-Object { [int](Get-NumericValueOrDefault (Get-JsonValue $_ "nr5SampleCount")) -gt 0 }).Count
                $actualReadyTraceCount = @($traceRecords | Where-Object { Test-Truthy (Get-JsonValue $_ "readyForBenchmarkTrace") }).Count
                $actualReadyNr5TraceCount = @($traceRecords | Where-Object { [int](Get-NumericValueOrDefault (Get-JsonValue $_ "nr5SampleCount")) -gt 0 -and (Test-Truthy (Get-JsonValue $_ "readyForBenchmarkTrace")) }).Count
                $actualCandidateReadyNr5TraceCount = @($traceRecords | Where-Object { [int](Get-NumericValueOrDefault (Get-JsonValue $_ "nr5SampleCount")) -gt 0 -and (Test-Truthy (Get-JsonValue $_ "candidateComparisonReady")) }).Count
                $mixedWeakStrongTraceRecords = @($traceRecords | Where-Object {
                        [int](Get-NumericValueOrDefault (Get-JsonValue $_ "nr5SampleCount")) -gt 0 -and
                        [int](Get-NumericValueOrDefault (Get-JsonValue $_ "weakInputSampleCount")) -gt 0 -and
                        [int](Get-NumericValueOrDefault (Get-JsonValue $_ "strongInputSampleCount")) -gt 0
                    })
                $mixedWeakStrongReadyTraceRecords = @($mixedWeakStrongTraceRecords | Where-Object {
                        (Test-Truthy (Get-JsonValue $_ "mixedWeakStrongEvidenceReady")) -and
                        (Test-Truthy (Get-JsonValue $_ "weakStrongOutputParityReady"))
                    })
                $mixedWeakStrongGapWatchTraceRecords = @($mixedWeakStrongTraceRecords | Where-Object {
                        -not (Test-Truthy (Get-JsonValue $_ "weakStrongOutputParityReady"))
                    })
                $mixedWeakStrongFieldMissingTraceCount = @($traceRecords | Where-Object {
                        [int](Get-NumericValueOrDefault (Get-JsonValue $_ "nr5SampleCount")) -gt 0 -and
                        ($null -eq (Get-JsonValue $_ "strongInputSampleCount") -or
                            $null -eq (Get-JsonValue $_ "mixedWeakStrongEvidenceReady") -or
                            $null -eq (Get-JsonValue $_ "weakStrongOutputParityReady") -or
                            [string]::IsNullOrWhiteSpace([string](Get-JsonValue $_ "mixedWeakStrongEvidenceStatus")))
                    }).Count
                $mixedWeakStrongMissingTraceCount = [Math]::Max(0, $actualNr5TraceCount - $mixedWeakStrongTraceRecords.Count)
                $mixedWeakStrongEvidenceStatus = if ($actualNr5TraceCount -le 0) {
                    "no-nr5-history"
                }
                elseif ($mixedWeakStrongTraceRecords.Count -eq 0) {
                    "missing-mixed-weak-strong"
                }
                elseif ($mixedWeakStrongReadyTraceRecords.Count -gt 0) {
                    "ready"
                }
                elseif ($mixedWeakStrongGapWatchTraceRecords.Count -gt 0) {
                    "weak-strong-output-gap-watch"
                }
                else {
                    "not-ready"
                }
                $agcStabilityTraceCount = 0
                $agcStabilityMissingTraceCount = 0
                $agcPumpingRiskTraceCount = 0
                $agcActivePumpingSignalCount = 0
                $agcVoiceLikePumpingSignalCount = 0
                $artifactControlFieldMissingTraceCount = 0
                $artifactControlSignalCount = 0
                foreach ($trace in @($traceRecords)) {
                    $agcStatus = [string](Get-JsonValue $trace "agcStabilityStatus")
                    $agcRiskValue = Get-JsonValue $trace "agcPumpingRisk"
                    if ([string]::IsNullOrWhiteSpace($agcStatus) -or $null -eq $agcRiskValue) {
                        $agcStabilityMissingTraceCount++
                    }
                    else {
                        $agcStabilityTraceCount++
                    }
                    if (Test-Truthy $agcRiskValue) {
                        $agcPumpingRiskTraceCount++
                    }
                    if ([int](Get-NumericValueOrDefault (Get-JsonValue $trace "nr5SampleCount")) -gt 0 -and
                        ($null -eq (Get-JsonValue $trace "nr5ArtifactRiskScore") -or
                            [string]::IsNullOrWhiteSpace([string](Get-JsonValue $trace "nr5ArtifactRiskStatus")) -or
                            $null -eq (Get-JsonValue $trace "nr5LowEvidenceLiftedSampleCount"))) {
                        $artifactControlFieldMissingTraceCount++
                    }
                    foreach ($signal in @(Get-JsonArray $trace "safetySignals")) {
                        $signalName = [string](Get-JsonValue $signal "name")
                        if ([string]::Equals($signalName, "agc-active-gain-movement-db", [StringComparison]::OrdinalIgnoreCase)) {
                            $agcActivePumpingSignalCount++
                        }
                        elseif ([string]::Equals($signalName, "agc-voice-like-gain-movement-db", [StringComparison]::OrdinalIgnoreCase)) {
                            $agcVoiceLikePumpingSignalCount++
                        }
                        elseif ([string]::Equals([string](Get-JsonValue $signal "safetyClass"), "artifact-control", [StringComparison]::OrdinalIgnoreCase)) {
                            $artifactControlSignalCount++
                        }
                    }
                }
                $agcStabilityStatus = if ($actualTraceCount -le 0) {
                    "no-traces"
                }
                elseif ($agcStabilityMissingTraceCount -eq 0) {
                    "agc-stability-ready"
                }
                else {
                    "agc-stability-missing"
                }
                $traceSourceCheckedCount = 0
                $traceSourceMissingCount = 0
                $traceSourceInvalidCount = 0
                $traceSourceJsonlMissingCount = 0
                $traceSourceSummaryHashPresentCount = 0
                $traceSourceSummaryHashMissingCount = 0
                $traceSourceSummaryHashMismatchCount = 0
                $traceSourceJsonlHashPresentCount = 0
                $traceSourceJsonlHashMissingCount = 0
                $traceSourceJsonlHashMismatchCount = 0
                $traceOrderingFieldsPresent = $false
                foreach ($trace in @($traceRecords)) {
                    if ($null -ne (Get-JsonValue $trace "traceSequenceUtc") -or $null -ne (Get-JsonValue $trace "sortKeySource")) {
                        $traceOrderingFieldsPresent = $true
                        break
                    }
                }
                if (-not $traceOrderingFieldsPresent) {
                    foreach ($trace in @($latestTrace, $previousNr5Trace, $bestBalancedTrace, $bestWeakSignalTrace, $lowestPumpingTrace)) {
                        if ($null -ne $trace -and ($null -ne (Get-JsonValue $trace "traceSequenceUtc") -or $null -ne (Get-JsonValue $trace "sortKeySource"))) {
                            $traceOrderingFieldsPresent = $true
                            break
                        }
                    }
                }
                $traceOrderingFieldsRequired = ($schemaVersion -ge 7 -or $traceOrderingFieldsPresent)
                $traceOrderingViolationCount = 0
                $validSortKeySources = @("trace-directory-timestamp", "completedUtc", "file-last-write-utc")
                $orderedTraceRecordsBySequence = @($traceRecords | Sort-Object `
                    @{ Expression = {
                        $sequence = Get-DateTimeOffsetValue (Get-JsonValue $_ "traceSequenceUtc")
                        if ($null -eq $sequence) { [Int64]::MinValue } else { $sequence.UtcDateTime.Ticks }
                    } }, `
                    @{ Expression = { [string](Get-JsonValue $_ "traceId") } })
                $orderedNr5TraceRecordsBySequence = @($orderedTraceRecordsBySequence | Where-Object { [int](Get-NumericValueOrDefault (Get-JsonValue $_ "nr5SampleCount")) -gt 0 })
                $expectedLatestTraceBySequence = $null
                if ($orderedNr5TraceRecordsBySequence.Count -gt 0) {
                    $expectedLatestTraceBySequence = $orderedNr5TraceRecordsBySequence[$orderedNr5TraceRecordsBySequence.Count - 1]
                }
                $expectedPreviousNr5TraceBySequence = $null
                if ($orderedNr5TraceRecordsBySequence.Count -gt 1) {
                    $expectedPreviousNr5TraceBySequence = $orderedNr5TraceRecordsBySequence[$orderedNr5TraceRecordsBySequence.Count - 2]
                }
                $allTraceSignals = New-Object System.Collections.Generic.List[object]
                $readinessFieldsPresent = ($aggregateReadinessGaps.Count -gt 0)
                foreach ($trace in @($traceRecords)) {
                    if (@(Get-JsonArray $trace "readinessGapSummary").Count -gt 0 -or @(Get-JsonArray $trace "safetyClassReadiness").Count -gt 0) {
                        $readinessFieldsPresent = $true
                    }
                    foreach ($signal in @(Get-JsonArray $trace "safetySignals")) {
                        $allTraceSignals.Add($signal) | Out-Null
                        foreach ($field in @("thresholdDirection", "unit", "readinessGap", "readinessMargin", "readinessGapUnit", "readinessGapScore")) {
                            if ($null -ne (Get-JsonValue $signal $field)) {
                                $readinessFieldsPresent = $true
                            }
                        }
                    }
                }
                $readinessFieldsRequired = ($schemaVersion -ge 2 -or $readinessFieldsPresent)
                $expectedAggregateSafetyClassCounts = @(New-LiveHistorySafetyClassCountsFromSignals -Signals @($allTraceSignals.ToArray()))
                $expectedAggregateReadinessGaps = @(New-LiveHistoryReadinessSummaryFromSignals -Signals @($allTraceSignals.ToArray()))
                $latestFullTrace = Get-LiveHistoryTraceRecordById -Records $traceRecords -TraceId ([string](Get-JsonValue $latestTrace "traceId"))
                $previousFullTrace = Get-LiveHistoryTraceRecordById -Records $traceRecords -TraceId ([string](Get-JsonValue $previousNr5Trace "traceId"))
                $expectedBestBalancedTrace = Select-LiveHistoryTraceForSummary -Records $traceRecords -Mode "best-balanced"
                $expectedBestWeakSignalTrace = Select-LiveHistoryTraceForSummary -Records $traceRecords -Mode "best-weak"
                $expectedLowestPumpingTrace = Select-LiveHistoryTraceForSummary -Records $traceRecords -Mode "lowest-pumping"
                $expectedMixedWeakStrongBestTrace = $null
                if ($mixedWeakStrongTraceRecords.Count -gt 0) {
                    $expectedMixedWeakStrongBestTrace = @($mixedWeakStrongTraceRecords | Sort-Object `
                            @{ Expression = { if (Test-Truthy (Get-JsonValue $_ "weakStrongOutputParityReady")) { 0 } else { 1 } } }, `
                            @{ Expression = { $value = Get-NumericValue (Get-JsonValue $_ "weakStrongOutputGapDb"); if ($null -eq $value) { 999.0 } else { [Math]::Abs([double]$value) } } }, `
                            @{ Expression = { if (Test-Truthy (Get-JsonValue $_ "candidateComparisonReady")) { 0 } else { 1 } } }, `
                            @{ Expression = { Get-NumericValue (Get-JsonValue $_ "safetyRiskScore") } })[0]
                }
                $bestBalancedFullTrace = $expectedBestBalancedTrace
                $bestWeakSignalFullTrace = $expectedBestWeakSignalTrace
                $lowestPumpingFullTrace = $expectedLowestPumpingTrace
                $expectedPromotionDecision = New-LiveHistoryExpectedPromotionDecision -Latest $latestFullTrace -BestBalanced $bestBalancedFullTrace -BestWeak $bestWeakSignalFullTrace -LowestPumping $lowestPumpingFullTrace
                $expectedPromotionRecommendedTraceId = [string](Get-JsonValue $expectedPromotionDecision "recommendedTraceId")
                $expectedPromotionReferenceTraceId = [string](Get-JsonValue $expectedPromotionDecision "referenceTraceId")
                $expectedPromotionReferenceTraceRole = [string](Get-JsonValue $expectedPromotionDecision "referenceTraceRole")
                $expectedReadinessTrend = Add-LiveHistoryReadinessTrendContext `
                    -Trend (New-LiveHistoryReadinessTrend -Latest $latestFullTrace -Previous $previousFullTrace) `
                    -ComparisonScope "latest-vs-previous" `
