                    -ComparisonScope "latest-vs-reference" `
                    -LatestTraceId ([string](Get-JsonValue $latestTrace "traceId")) `
                    -ReferenceTraceId $expectedPromotionReferenceTraceId `
                    -ReferenceTraceRole $expectedPromotionReferenceTraceRole `
